function convertDateRange(dateRange) {
	// Split the date range into start and end dates
	const [startMonth, startYear, endMonth, endYear] = dateRange.split(/,\s*/)
	// Get the first day of the start month/year
	const startDate = new Date(`${startMonth} 1, ${startYear}`)
	// Get the last day of the end month/year
	const endDate = new Date(`${endMonth} 1, ${endYear}`)
	endDate.setMonth(endDate.getMonth() + 1)
	endDate.setDate(0)
	// Format the dates as strings
	const startDateString = `${startDate.getMonth() + 1}/${startDate.getDate()}/${startDate.getFullYear()}`
	const endDateString = `${endDate.getMonth() + 1}/${endDate.getDate()}/${endDate.getFullYear()}`
	// Return the formatted date range
	return `${startDateString} - ${endDateString}`
}

function getscorecardpermission() {
	$.ajax({
		type: "GET",
		url: "/stratroom/user/modulePermissions?moduleName=Scorecard",
		async: false,
		success: function (data) {
			if (data.Scorecard != undefined && !jQuery.isEmptyObject(data.Scorecard)) {
				//kpi view
				$.each(data.Scorecard, function (forindex, fordata) {
					if (forindex == "KPI View") {
						if (fordata.privilegeCreate != undefined && fordata.privilegeCreate == "TRUE") {
							kpicreatepermission = true;
						}

						if (fordata.privilegeUpdate != undefined && fordata.privilegeUpdate == "TRUE") {
							kpieditpermission = true;
						}

						if (fordata.privilegeDelete != undefined && fordata.privilegeDelete == "TRUE") {
							kpideletepermission = true;
						}

						if (fordata.privilegeView != undefined && fordata.privilegeView == "TRUE") {
							kpiviewpermission = true;
						}
					}
				});
			}
		}
	});
}

function getcockpitpermission() {
	$.ajax({
		type: "GET",
		url: "/stratroom/user/modulePermissions?moduleName=Cockpit",
		async: false,
		success: function (data) {
			if (data.Cockpit != undefined && !jQuery.isEmptyObject(data.Cockpit)) {
				dashboardmodPermission = data.Cockpit.Charts;
				//text
				if (data.Cockpit.Text.privilegeCreate != undefined && data.Cockpit.Text.privilegeCreate == "TRUE") {
					textcreatepermission = true;
				}
				if (data.Cockpit.Text.privilegeUpdate != undefined && data.Cockpit.Text.privilegeUpdate == "TRUE") {
					texteditpermission = true;
				}
				if (data.Cockpit.Text.privilegeDelete != undefined && data.Cockpit.Text.privilegeDelete == "TRUE") {
					textdeletepermission = true;
				}
				if (data.Cockpit.Text.privilegeView != undefined && data.Cockpit.Text.privilegeView == "TRUE") {
					textviewpermission = true;
				}
				//table
				if (data.Cockpit.Table.privilegeCreate != undefined && data.Cockpit.Table.privilegeCreate == "TRUE") {
					tablecreatepermission = true;
				}
				if (data.Cockpit.Table.privilegeUpdate != undefined && data.Cockpit.Table.privilegeUpdate == "TRUE") {
					tableeditpermission = true;
				}
				if (data.Cockpit.Table.privilegeDelete != undefined && data.Cockpit.Table.privilegeDelete == "TRUE") {
					textdeletepermission = true;
				}
				if (data.Cockpit.Table.privilegeView != undefined && data.Cockpit.Table.privilegeView == "TRUE") {
					tableviewpermission = true;
				}
			}
		}
	});
}

function getcolumnView() {
	$.ajax({
		type: "GET",
		url: "/stratroom/pages/" + pageNo,
		async: false,
		success: function (data) {
			if ($("#userPrincipal").val() != $("#userPrincipalnavigate").val()) {
				$(".subusermenuname").text(data.pageName);
				if ($(".superusertopmenu").hasClass(data.id)) {
					$("." + data.id).addClass("homepageHighlight");
				}
			}
			pagelayout = (data.columnType != undefined && data.columnType != "" && data.columnType != null ? data.columnType.toLocaleLowerCase() : "two");
		}
	});
}

