function dateformatyymmdd(newdate) {
	var dt = new Date(newdate);
	var mm = dt.getMonth() + 1;
	var dd = dt.getDate();
	var yyyy = dt.getFullYear();
	return yyyy + '-' + mm + '-' + dd;
}

