$(document).ready(function () {
  // Define the HTML content for One and Two
  const contentOne = `
    <div class="form-group browser-default col-12">
      <select id="widget_type" name="widget_type" class="form-control valid" aria-invalid="false">
        <option value="Chart" data-i18n="Chart">Chart</option>
        <option value="Table">Table</option>
      </select>
    </div>
  `;

  const contentTwo = `
    <div class="form-group browser-default col-12">
      <select id="widget_type" name="widget_type" class="form-control valid" aria-invalid="false">
        <option value="Charts" data-i18n="Charts">Charts</option>
        <option value="Drilldown" data-i18n="Drilldown Chart">Drilldown Chart</option>
      </select>
    </div>
  `;

  // Handle button clicks
  $('#btn-one').click(function () {
    $('#widget_options_container').html(contentOne);
    $('#btn-one').addClass('active');
    $('#btn-two').removeClass('active');
  });

  $('#btn-two').click(function () {
    $('#widget_options_container').html(contentTwo);
    $('#btn-two').addClass('active');
    $('#btn-one').removeClass('active');
  });

  // Optional: Trigger default state
  $('#btn-one').trigger('click');
});
 
