function getreportee() {

	if (jQuery.isEmptyObject(reporteelist)) {
		$.ajax({
			url: "/stratroom/reporteeList",
			async: false,
			success: function (employeeList) {
				reporteelist = employeeList;
			}
		});
	}
}
function textjsonform(id, action, type) {

    var bgcolor = "";
    var image = "";

    if (type === "normalTextType4") {
        image = "images/hash-i.svg";
        bgcolor = "bg-pink";
    } else if (type === "normalTextType3") {
        bgcolor = "bg-purple";
    } else if (type === "normalTextType2") {
        image = "images/percent-i.svg";
        bgcolor = "bg-green";
    } else {
        image = "images/dollar-i.svg";
        bgcolor = "bg-blue";
    }

    var iconselect = $("#icon_select").val();
    var currency = "$";
    var dataType = "currency";
    var cardtypesymbol = "fas fa-dollar-sign";

    if (iconselect.includes("%")) {
        currency = "%";
        dataType = "percentage";
        cardtypesymbol = "fas fa-percent";
    } else if (iconselect.includes("#")) {
        currency = "#";
        dataType = "number";
        cardtypesymbol = "fas fa-hashtag";
    }

    var period = $("#period").val() || $(".top_datepicker").val();

    return {
        active: 0,
        owner: currentEmp,
        pageId: pageNo,
        dashBoardPreferencesValue: {
            type: type,
            displayname: $("#displayname").val(),
            cardtypeselect: $("#card_type_select").val(),
            iconselect: iconselect,
            currency: currency,
            bgcolor: bgcolor,
            cardtypesymbol: cardtypesymbol,
            dataType: dataType,
            deptName: $("#department").val(),
            empployeeIds: [currentEmp],
            formula: $("#text_formula_widget").val(),
            fieldName: $("#kpiFieldName").val(),
            period: period
        }
    };
}

