function savekpidrillTable(id, action, display, tabletypefield) {
	console.log(tabletypefield,"tabletypefield")
	var textObj = ""
	if (tabletypefield == "kpidrilltable") {
		textObj = datatablekpidrilljsonform(id, action);
	} else if (tabletypefield == "kpistatuscount") {
		textObj = datatablekpistatusjsonform(id, action);

	} else if (tabletypefield == "projectstatuscount") {
		textObj = datatableprojectstatusjsonform(id, action);

	}
	else if (tabletypefield == "reviewmonitoringtable") {
		textObj = reviewmonitoringjsonform(id, action);

	}
	else if (tabletypefield == "ermriskregistertable") {
		textObj = ermriskregjsonform(id, action);

	}
	else if (tabletypefield == "riskeventfreqTable") {
		textObj = riskEventFrequencyjsonform(id, action);

	}
	else if (tabletypefield == "criticaltable") {
		textObj = criticaljsonform(id, action);

	}
	else if (tabletypefield == "initiativeCount") {
		textObj = datatableinitiativeprogressjsonform(id, action);

	}
	else if (tabletypefield == "blankinitiativeCount") {
		textObj = datatableinitiativenoprogressjsonform(id, action);

	}
	else if (tabletypefield == "blankkpireports") {
		textObj = datatableblankkpijsonform(id, action);

	}
	if (textObj.dashBoardPreferencesValue.chartdisplayname == "") {
		textObj.dashBoardPreferencesValue.chartdisplayname = display;
	}
	var methodType = 'post';
	if (action == "edit") {
		methodType = 'put';
		textObj.id = (id != "" ? id : "");
	}


	console.log(textObj,"tabletypefield");


	$.ajax({
		url: "/stratroom/dashBoardPreferences",
		type: methodType,
		contentType: "application/json",
		data: JSON.stringify(textObj),
		success: function (data, status) {
			location.reload(true);
		},
		error: readErrorMsg
	});
}


function colorcodevalue(colorvalue) {
	var color = "#000000";
	if (colorvalue != "" && colorvalue != undefined) {
		var colorstartposition = colorvalue.indexOf("rgb");
		var colorendposition = colorvalue.indexOf(")") + 1;
		if (colorstartposition != -1 && colorendposition != -1) {
			color = colorvalue.substr(colorstartposition, colorendposition);
		} else {
			color = colorvalue;
		}
	}
	return color;
}

