function handleReviewTableevent(id, action, headertype) {

	$("#review_register_Form").trigger('reset');
	$("#review_register_Form input[name='action']").val(action);
	$('#review_register_Form textarea').removeAttr("disabled");
	$('#review_register_Form input[type="text"]').removeAttr("disabled");
	$('#review_register_Form input[type="checkbox"]').removeAttr("disabled");
	$('#review_register_Form select').removeAttr("disabled");
	$("#existreviewid").val('');
	if (action == 'add') {
		formvalidationerrorreset();
	} else if (action == 'delete') {
		$("#deleterecordid").val(id);
		$('#deleteModaldashboard').modal('toggle');

		$(window).on("resize", function () {
			$(".modal:visible").each(alignModal);
		});
		$(".modal").on("shown.bs.modal", alignModal);

	} else { // view and edit
		formvalidationerrorreset();
		if (action == 'edit') {
			$("#existreviewid").remove();
			$("#review_register_Form #reviewregisterid").val(id);
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: dashboardReviewRegisterPopSuccessCallback,
				error: readErrorMsg
			});
		}
		if (action == 'view') {
			$("#viewtableriskinitiativeheader").html("View Review Register");
			$('#review_register_Form textarea').attr("disabled", true);
			$('#review_register_Form input[type="text"]').attr("disabled", true);
			$('#review_register_Form input[type="checkbox"]').attr("disabled", true);
			$('#review_register_Form select').attr("disabled", true);
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data) {
					dashboardReviewRegisterViewSuccessCallback(data, 'view', 'review');
				},
				error: readErrorMsg
			});
		} else if (action == 'download') {
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data, status) {
					dashboardReviewRegisterViewSuccessCallback(data, 'download', 'review');
				},
				error: readErrorMsg
			});
		} else if (action == 'csvdownload') {
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data, status) {
					dashboardReviewRegisterViewSuccessCallback(data, 'csvdownload', 'review');
				},
				error: readErrorMsg
			});
		}
	}
}
function dashboardReviewRegisterPopSuccessCallback(data) {
    console.log(data, "data");
	updateDescription = data;
	
	$('.reviewdepartmentmulti').empty();
	$('.reviewnamesmulti').empty();
	$("#review_register_Form").append('<input type="hidden" id="existreviewid" value="" />');
	// var dept	=	$("#userdept").val();
	
	populateDeptReporteeList();
	if (data.dashBoardPreferencesValue.department) {
		let deptIds = data.dashBoardPreferencesValue.department.split(',');
		setTimeout(() => {
			$(".reviewdepartmentmulti").val(deptIds).trigger('change');
		}, 500); // Allow time for populateDeptReporteeList to complete
	}
	
	if (data.dashBoardPreferencesValue.reviewstatus) {
		let reviewStatus = data.dashBoardPreferencesValue.reviewstatus.split(',');
		setTimeout(() => {
			$(".reviewstatusmulti").val(reviewStatus).trigger('change');
		}, 500); 
	}

	
	
	if (data.dashBoardPreferencesValue.department) {
			let deptIds = data.dashBoardPreferencesValue.department.split(',');
			getRiskByDeptId('.reviewnamesmulti', deptIds);
	
			if (data.dashBoardPreferencesValue.reviewnames) {
				let selectedRisks = data.dashBoardPreferencesValue.reviewnames.split(',');
				setTimeout(() => {
					$(".reviewnamesmulti").val(selectedRisks).trigger('change');
					$("#existreviewid").val(data.dashBoardPreferencesValue.reviewnames);
				}, 1000);
			}
		}
	

	$('#review_register_Form #reviewregisterid').val(data.id);
	if (data.dashBoardPreferencesValue.departmentName != undefined && data.dashBoardPreferencesValue.departmentName == true) {
		$("#review_register_Form #departmentName").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.reviewcode != undefined && data.dashBoardPreferencesValue.reviewcode == true) {
		$("#review_register_Form #reviewCode").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.reviewName != undefined && data.dashBoardPreferencesValue.reviewName == true) {
		$("#review_register_Form #reviewName").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.mitigation != undefined && data.dashBoardPreferencesValue.mitigation == true) {
		$("#review_register_Form #reviewMitigation").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.notes != undefined && data.dashBoardPreferencesValue.notes == true) {
		$("#review_register_Form #reviewNotes").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.targetcompletion != undefined && data.dashBoardPreferencesValue.targetcompletion == true) {
		$("#review_register_Form #reviewTarget").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.changesintarget != undefined && data.dashBoardPreferencesValue.changesintarget == true) {
		$("#review_register_Form #reviewTargetChanges").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.progress != undefined && data.dashBoardPreferencesValue.progress == true) {
		$("#review_register_Form #reviewProgress").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.status != undefined && data.dashBoardPreferencesValue.status == true) {
		$("#review_register_Form #reviewStatus").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.personincharge != undefined && data.dashBoardPreferencesValue.personincharge == true) {
		$("#review_register_Form #reviewPersonIncharge").prop('checked', true);
	}

	$("#reviewtabletypeField").val('reviewmonitoringtable');
}

