function handleRiskEventFrequencyTable(id, action, headertype) {

	$("#riskeventfreq_Form").trigger('reset');
	$("#riskeventfreq_Form input[name='action']").val(action);
	$('#riskeventfreq_Form textarea').removeAttr("disabled");
	$('#riskeventfreq_Form input[type="text"]').removeAttr("disabled");
	$('#riskeventfreq_Form input[type="checkbox"]').removeAttr("disabled");
	$('#riskeventfreq_Form select').removeAttr("disabled");
	$("#existriskfrequencyid").val('');
	if (action == 'add') {
		formvalidationerrorreset();
	} else if (action == 'delete') {
		$("#deleterecordid").val(id);
		$('#deleteModaldashboard').modal('toggle');

		$(window).on("resize", function () {
			$(".modal:visible").each(alignModal);
		});
		$(".modal").on("shown.bs.modal", alignModal);

	} else { // view and edit
		formvalidationerrorreset();
		if (action == 'edit') {
			$("#existriskfrequencyid").remove();
			$("#riskeventfreq_Form #riskeventfreqregisterid").val(id);
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: dashboardRiskEventFrequencyPopSuccessCallback,
				error: readErrorMsg
			});
		}
		if (action == 'view') {
			$("#viewtableriskinitiativeheader").html("View Risk Events Frequency of Occurrence");
			$('#riskeventfreq_Form textarea').attr("disabled", true);
			$('#riskeventfreq_Form input[type="text"]').attr("disabled", true);
			$('#riskeventfreq_Form input[type="checkbox"]').attr("disabled", true);
			$('#riskeventfreq_Form select').attr("disabled", true);
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data) {
					dashboardRiskEventFrequencyViewSuccessCallback(data, 'view', 'riskEventFrequency');
				},
				error: readErrorMsg
			});
		} else if (action == 'download') {
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data, status) {
					dashboardRiskEventFrequencyViewSuccessCallback(data, 'download', 'riskEventFrequency');
				},
				error: readErrorMsg
			});
		} else if (action == 'csvdownload') {
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data, status) {
					dashboardRiskEventFrequencyViewSuccessCallback(data, 'csvdownload', 'riskEventFrequency');
				},
				error: readErrorMsg
			});
		}
	}
}

function dashboardRiskEventFrequencyPopSuccessCallback(data) {

	updateDescription = data;
	
	$('#Riskeventfreqdept').empty();
	$('#riskeventfreqpagenames').empty();
	$("#riskeventfreq_Form").append('<input type="hidden" id="existriskfrequencyid" value="" />');

// Populate Departments
populateDeptReporteeList();
if (data.dashBoardPreferencesValue.department) {
	let deptIds = data.dashBoardPreferencesValue.department.split(',');
	setTimeout(() => {
		$("#Riskeventfreqdept").val(deptIds).trigger('change');
	}, 500); // Allow time for populateDeptReporteeList to complete
}


	if (data.dashBoardPreferencesValue.department) {
		let deptIds = data.dashBoardPreferencesValue.department.split(',');
		getRiskEventFrequencyByDeptId('#riskeventfreqpagenames', deptIds);

		if (data.dashBoardPreferencesValue.riskEventfreqnames) {
			let selectedRisks = data.dashBoardPreferencesValue.riskEventfreqnames.split(',');
			setTimeout(() => {
				$("#riskeventfreqpagenames").val(selectedRisks).trigger('change');
				$("#existriskfrequencyid").val(data.dashBoardPreferencesValue.riskEventfreqnames);
			}, 1000);
		}
	}


	$('#riskeventfreq_Form #riskeventfreqregisterid').val(data.id);

	if (data.dashBoardPreferencesValue.departmentName != undefined && data.dashBoardPreferencesValue.departmentName == true) {
		$("#riskeventfreq_Form #riskeventfreqdepartmentName").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.riskEventName != undefined && data.dashBoardPreferencesValue.riskEventName == true) {
		$("#riskeventfreq_Form #riskEventFreqName").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.frequency != undefined && data.dashBoardPreferencesValue.frequency == true) {
		$("#riskeventfreq_Form #riskEventFrequency").prop('checked', true);
	}

	$("#riskeventfreqtabletypeField").val('riskeventfreqTable');
}

