function handlePosTradingTableevent(id, action, headertype) {

	$("#posTrading_Form").trigger('reset');
	$("#posTrading_Form input[name='action']").val(action);
	$('#posTrading_Form textarea').removeAttr("disabled");
	$('#posTrading_Form input[type="text"]').removeAttr("disabled");
	$('#posTrading_Form input[type="checkbox"]').removeAttr("disabled");
	$('#posTrading_Form select').removeAttr("disabled");
	$("#existpostradingid").val('');
	if (action == 'add') {
		formvalidationerrorreset();
	} else if (action == 'delete') {
		$("#deleterecordid").val(id);
		$('#deleteModaldashboard').modal('toggle');

		$(window).on("resize", function () {
			$(".modal:visible").each(alignModal);
		});
		$(".modal").on("shown.bs.modal", alignModal);

	} else { // view and edit
		formvalidationerrorreset();
		if (action == 'edit') {
			$("#existpostradingid").remove();
			$("#posTrading_Form #posTradingregisterid").val(id);
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: dashboardPosTradingRegisterPopSuccessCallback,
				error: readErrorMsg
			});
		}
		if (action == 'view') {
			$("#viewtableriskinitiativeheader").html("View Business Process Based on Trading Hours Setting");
			$('#posTrading_Form textarea').attr("disabled", true);
			$('#posTrading_Form input[type="text"]').attr("disabled", true);
			$('#posTrading_Form input[type="checkbox"]').attr("disabled", true);
			$('#posTrading_Form select').attr("disabled", true);
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data) {
					dashboardPosTradingRegisterViewSuccessCallback(data, 'view', 'postrading');
				},
				error: readErrorMsg
			});
		} else if (action == 'download') {
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data, status) {
					dashboardPosTradingRegisterViewSuccessCallback(data, 'download', 'postrading');
				},
				error: readErrorMsg
			});
		} else if (action == 'csvdownload') {
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data, status) {
					dashboardPosTradingRegisterViewSuccessCallback(data, 'csvdownload', 'postrading');
				},
				error: readErrorMsg
			});
		}
	}
}
function dashboardPosTradingRegisterPopSuccessCallback(data) {

	updateDescription = data;
	//populateDeptList('.departmentmulti');
	$('.posTradingdepartmentmulti').empty();
	$('.posTradingnamesmulti').empty();
	$("#posTrading_Form").append('<input type="hidden" id="existpostradingid" value="" />');

	populateDeptReporteeList();
	if (data.dashBoardPreferencesValue.department) {
		let deptIds = data.dashBoardPreferencesValue.department.split(',');
		setTimeout(() => {
			$(".posTradingdepartmentmulti").val(deptIds).trigger('change');
		}, 500); // Allow time for populateDeptReporteeList to complete
	}

	if (data.dashBoardPreferencesValue.department) {
		let deptIds = data.dashBoardPreferencesValue.department.split(',');
		getposnameDeptId('.posTradingnamesmulti', deptIds);

		if (data.dashBoardPreferencesValue.postradingnames) {
			let selectedRisks = data.dashBoardPreferencesValue.postradingnames.split(',');
			setTimeout(() => {
				$(".posTradingnamesmulti").val(selectedRisks).trigger('change');
				$("#existpostradingid").val(data.dashBoardPreferencesValue.postradingnames);
			}, 1000);
		}
	}

	$('#posTrading_Form #posTradingregisterid').val(data.id);

	if (data.dashBoardPreferencesValue.departmentName != undefined && data.dashBoardPreferencesValue.departmentName == true) {
		$("#posTrading_Form #deptPosTrading").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.classification != undefined && data.dashBoardPreferencesValue.classification == true) {
		$("#posTrading_Form #posTradingClassification").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.timeCritical != undefined && data.dashBoardPreferencesValue.timeCritical == true) {
		$("#posTrading_Form #posTimeCrtical").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.amountService != undefined && data.dashBoardPreferencesValue.amountService == true) {
		$("#posTrading_Form #posTradingAmountService").prop('checked', true);
	}



	$("#posTradingtabletypeField").val('postradingtable');
}
