// HTML for the dropdown item
// <li>
//     <a class="dropdown-item" href="#" onclick="loadDataAndGeneratePDF()">Download PDF</a>
// </li>
function handleCriticalTableevent(id, action, headertype) {

	$("#critical_register_Form").trigger('reset');
	$("#critical_register_Form input[name='action']").val(action);
	$('#critical_register_Form textarea').removeAttr("disabled");
	$('#critical_register_Form input[type="text"]').removeAttr("disabled");
	$('#critical_register_Form input[type="checkbox"]').removeAttr("disabled");
	$('#critical_register_Form select').removeAttr("disabled");
	$("#existcriticalid").val('');
	if (action == 'add') {
		formvalidationerrorreset();
	} else if (action == 'delete') {
		$("#deleterecordid").val(id);
		$('#deleteModaldashboard').modal('toggle');

		$(window).on("resize", function () {
			$(".modal:visible").each(alignModal);
		});
		$(".modal").on("shown.bs.modal", alignModal);

	} else { // view and edit
		formvalidationerrorreset();
		if (action == 'edit') {
			$("#existcriticalid").remove();
			$("#critical_register_Form #criticalregisterid").val(id);
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: dashboardCriticalRegisterPopSuccessCallback,
				error: readErrorMsg
			});
		}
		if (action == 'view') {
			$("#viewtableriskinitiativeheader").html("View Process Business Critical");
			$('#critical_register_Form textarea').attr("disabled", true);
			$('#critical_register_Form input[type="text"]').attr("disabled", true);
			$('#critical_register_Form input[type="checkbox"]').attr("disabled", true);
			$('#critical_register_Form select').attr("disabled", true);
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data) {
					dashboardCriticalRegisterViewSuccessCallback(data, 'view', 'critical');
				},
				error: readErrorMsg
			});
		} else if (action == 'download') {
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data, status) {
					dashboardCriticalRegisterViewSuccessCallback(data, 'download', 'critical');
				},
				error: readErrorMsg
			});
		} else if (action == 'csvdownload') {
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: function (data, status) {
					dashboardCriticalRegisterViewSuccessCallback(data, 'csvdownload', 'critical');
				},
				error: readErrorMsg
			});
		}
	}
}


function dashboardCriticalRegisterPopSuccessCallback(data) {
	updateDescription = data;

	$('.criticalbusinessnamesmulti').empty();
	$('.criticaldepartmentmulti').empty();
	
	$("#critical_register_Form").append('<input type="hidden" id="existcriticalid" value="" />');

	// Populate Departments
	populateDeptReporteeList();
	if (data.dashBoardPreferencesValue.department) {
		let deptIds = data.dashBoardPreferencesValue.department.split(',');
		setTimeout(() => {
			$(".criticaldepartmentmulti").val(deptIds).trigger('change');
		}, 500); // Allow time for populateDeptReporteeList to complete
	}

	if (data.dashBoardPreferencesValue.department) {
		let deptIds = data.dashBoardPreferencesValue.department.split(',');
		getCriticalnameDeptId('.criticalbusinessnamesmulti', deptIds);

		if (data.dashBoardPreferencesValue.criticalnames) {
			let selectedRisks = data.dashBoardPreferencesValue.criticalnames.split(',');
			setTimeout(() => {
				$(".criticalbusinessnamesmulti").val(selectedRisks).trigger('change');
				$("#existcriticalid").val(data.dashBoardPreferencesValue.criticalnames);
			}, 1000);
		}
	}

	

	$('#critical_register_Form #criticalregisterid').val(data.id);
	if (data.dashBoardPreferencesValue.departmentName) {
		$("#critical_register_Form #deptCritical").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.critical) {
		$("#critical_register_Form #totalCritical").prop('checked', true);
	}
	if (data.dashBoardPreferencesValue.lesscritical) {
		$("#critical_register_Form #lessCritical").prop('checked', true);
	}
	$("#criticaltabletypeField").val('criticaltable');
}

