let branch_all = [];

function formatResult(state) {

	if (!state.id) {
		var btn = $('<div class="text-right"><button id="all-branch" style="margin-right: 10px;" class="btn btn-default">Select All</button><button id="clear-branch" class="btn btn-default">Clear All</button></div>')
		return btn;
	}

	branch_all.push(state.id);
	var id = 'kpinamesmulti' + state.id;
	var checkbox = $('<div class="checkbox"><input class="' + id + '" type="checkbox" ' + (state.selected ? 'checked' : '') + '><label class="select2labelelem" for="checkbox1">' + state.text + '</label></div>', { id: id });
	return checkbox;
}

function arr_diff(a1, a2) {
	var a = [], diff = [];
	for (var i = 0; i < a1.length; i++) {
		a[a1[i]] = true;
	}
	for (var i = 0; i < a2.length; i++) {
		if (a[a2[i]]) {
			delete a[a2[i]];
		} else {
			a[a2[i]] = true;
		}
	}
	for (var k in a) {
		diff.push(k);
	}
	return diff;
}

function populatekpinames(data, type, statuslight, existselectedid, categorytype) {
    console.log(data, "kpidataa");

    $('.kpinamesmulti').empty();
    var existkpi = false;
    var kpioptions = [];
    let branch_all = [];

    // Extract cardDetailsDTO from each data item
    const cardDetailsDTOs = data.map(item => item.cardDetailsDTO);
    console.log(cardDetailsDTOs, "Extracted cardDetailsDTOs");

    cardDetailsDTOs.forEach(cardDetails => {
        if (cardDetails && cardDetails.scoreCardDTOS) {
            cardDetails.scoreCardDTOS.forEach(scorecard2 => {
                console.log(scorecard2, "kpiscr2");

                scorecard2.objectiveList.forEach(scorecard3 => {
                    console.log(scorecard3, "kpiscr3");

                    scorecard3.kpiList.forEach(scorecard4 => {
                        console.log(scorecard4, "kpiscr4");

                        existkpi = true;
                        if (categorytype === "all" || 
                            (statuslight.length && type === "old" && existselectedid.length) || 
                            (statuslight.length === 0 && type === "old" && existselectedid.length) || 
                            type === "new") {

                            kpioptions.push({ "name": scorecard4.kpiValue.name, "id": scorecard4.id });
                            branch_all.push(scorecard4.id);
                        }
                    });
                });
            });
        }
    });

    // Add options to the .kpinamesmulti select element
    if (categorytype === "all") {
        addOption('.kpinamesmulti', "All", "All");
        kpioptions.forEach(option => addOption('.kpinamesmulti', option.name, option.id));
        $(".kpinamesmulti").val('All').trigger("change");
    } else if (type === "old" && existkpi) {
        if (statuslight.length && existselectedid.length || statuslight.length === 0 && existselectedid.length) {
            addOption('.kpinamesmulti', "All", "All");
            kpioptions.forEach(option => addOption('.kpinamesmulti', option.name, option.id));
            $(".kpinamesmulti").val(existselectedid);
        }
    } else if (type === "new" && existkpi) {
        addOption('.kpinamesmulti', "All", "All");
        kpioptions.forEach(option => addOption('.kpinamesmulti', option.name, option.id));
    }

    // Initialize select2 with options
    let optionSelect2 = {
        templateResult: formatResult,
        closeOnSelect: false,
        width: '100%'
    };

    $(".kpinamesmulti").select2(optionSelect2);
}


var scrollTop;

$(".kpinamesmulti").on("select2:selecting", function (event) {
	var $pr = $('.' + event.params.args.data._resultId).parent();
	scrollTop = $pr.prop('scrollTop');
});

$(".kpinamesmulti").on("select2:select", function (event) {
	$(window).scroll();
	var $pr = $('.' + event.params.data._resultId).parent();
	$pr.prop('scrollTop', scrollTop);
	if ($.inArray('All', $(this).val()) != -1) {
		$("li.select2-results__option").find("input:checkbox").prop("checked", true)
		$('.kpinamesmulti').val('All').trigger("change");
	} else {
		$(this).val().map(function (index) {
			$(".kpinamesmulti" + index).prop('checked', true);
		});
	}
});

$(".kpinamesmulti").on("select2:unselecting", function (event) {
	var $pr = $('.' + event.params.args.data._resultId).parent();
	scrollTop = $pr.prop('scrollTop');
});

$(".kpinamesmulti").on("select2:unselect", function (event) {
	$(window).scroll();

	var $pr = $('.' + event.params.data._resultId).parent();
	$pr.prop('scrollTop', scrollTop);
	var branch = $(this).val() ? $(this).val() : [];

	/*if($.inArray('All',$(this).val()) !=	-1){
		$("li.select2-results__option").find("input:checkbox").prop("checked",false)
		var values	=	$("#kpinamesmultiexist").val().split(',');
		for(i=0;i<=values.length;i++){
			if(values[i]	==	"All"){
				//values.splice(i,1);
				//$(".kpinamesmulti").val(values).trigger("change");
				//return false;
			}else{
				flag	=	true;
				branch.push(values[i]);
			}
		}
	}*/

	var branch_diff = arr_diff(branch_all, branch);
	branch_diff.map(function (index) {
		$(".kpinamesmulti" + index).prop('checked', false);
	});
	if (branch.length == 0) {
		var values = $("#kpinamesmultiexist").val().split(',');
		for (i = 0; i <= values.length; i++) {
			if (values[i] != "All") {
				branch.push(values[i]);
			}
		}
		branch.map(function (index) {
			$(".kpinamesmulti" + index).prop('checked', true);
		});
		$(".kpinamesmulti").val(branch).trigger("change");
	}
});


