function handleHeatmapTableevent(id, action, headertype) {
	if (headertype == "HeatMap") {
		$("#existheatmapid").val('');
		$("#heatmap_register_Form").trigger('reset');
		$("#heatmap_register_Form input[name='action']").val(action);
	}
	if (headertype == "GanttChart") {
		$("#existgantid").val('');
		$("#gantt_register_Form").trigger('reset');
		$("#gantt_register_Form input[name='action']").val(action);
	}
	if (action == 'add') {
		$("#existheatmapid").remove();
		$("#existgantid").remove();
		formvalidationerrorreset();
	} else if (action == 'delete') {
		$("#deleterecordid").val(id);
		$('#deleteModaldashboard').modal('toggle');

		$(window).on("resize", function () {
			$(".modal:visible").each(alignModal);
		});
		$(".modal").on("shown.bs.modal", alignModal);

	} else { // view and edit
		formvalidationerrorreset();
		if (action == 'edit') {
			if (headertype == "HeatMap") {
				$("#heatmap_register_Form #heatmapidid").val(id);
				$.ajax({
					url: "/stratroom/dashBoardPreferences/" + id,
					success: dashboardHeatmapPopSuccessCallback,
					error: readErrorMsg
				});
			} else if (headertype == "GanttChart") {
				$("#gantt_register_Form #ganttid").val(id);
				$.ajax({
					url: "/stratroom/dashBoardPreferences/" + id,
					success: dashboardGanttRegisterPopSuccessCallback,
					error: readErrorMsg
				});
			}
		}
		if (action == 'view') {
			if (headertype == "HeatMap") {
				$.ajax({
					url: "/stratroom/dashBoardPreferences/" + id,
					success: function (data) {
						heatmapchartviewSuccesscallback(data, 'view');
					},
					error: readErrorMsg
				});
			} else if (headertype == "GanttChart") {
				$.ajax({
					url: "/stratroom/dashBoardPreferences/" + id,
					success: function (data) {
						ganttchartviewSuccesscallback(data, 'view');
					},
					error: readErrorMsg
				});
			}
		}
	}
}


