function handleChartevent(id, action) {
	$("#dashbard_chart_Form").css('display', 'none');
	$("#dashbard_chart_Form").trigger('reset');
	$("#dashbard_chart_Form input[name='action']").val(action);

	if (action == 'add') {
		// when adding
		$("#dashbard_chart_Form").css('display', 'block');
		formvalidationerrorreset();
	} else if (action == 'delete') {
		if (deletepermission == false) {
			return false;
		}
		$("#deleterecordid").val(id);
		$('#deleteModaldashboard').modal('toggle');

		$(window).on("resize", function () {
			$(".modal:visible").each(alignModal);
		});
		$(".modal").on("shown.bs.modal", alignModal);

	} else { // view and edit
		$("#dashbard_chart_Form").css('display', 'block');
		formvalidationerrorreset();
		if (action == 'edit') {
			if (editpermission == false && createpermission == false) {
				return false;
			}
			$("#dashbard_chart_Form input[name='id']").val(id);
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: dashboardChartPopSuccessCallback,
				error: readErrorMsg
			});
		}
		if (action == 'view') {
			if (viewpermission == false) {
				return false;
			}
			$.ajax({
				url: "/stratroom/dashBoardPreferences/" + id,
				success: chartviewSuccesscallback,
				error: readErrorMsg
			});
		}
	}
}

function chartviewSuccesscallback(item) {
	var layoutType = item.dashBoardPreferencesValue.type;
	var chartdisplayname = (item.dashBoardPreferencesValue.displayname != undefined ? item.dashBoardPreferencesValue.displayname : "");
	var chartsettings = item.dashBoardPreferencesValue.chartsettings;
	var fieldName = ((item.dashBoardPreferencesValue.fieldName != undefined && item.dashBoardPreferencesValue.fieldName != "") ? item.dashBoardPreferencesValue.fieldName : "");
	var datarangechart = ((item.dashBoardPreferencesValue.datarangechart != undefined && item.dashBoardPreferencesValue.datarangechart != "") ? item.dashBoardPreferencesValue.datarangechart : $("#datePeriod").val());
	var measurement = ((item.dashBoardPreferencesValue.measurement != undefined && item.dashBoardPreferencesValue.measurement != "") ? item.dashBoardPreferencesValue.measurement : "Monthly");

	var chartdataloadval = [];
	var chartaxisfield = [];
	var checkdecimalornot = false;
	var percentage = false;
	var millions = false;
	var currencyval = "$";
	var colors = [];

	if (chartsettings != undefined && chartsettings != '' && chartsettings.length != 0) {
		$.each(chartsettings, function (i, List) {
			var chartdataload = {};
			var displayname = (List.displayname != undefined ? List.displayname : "");
			var chartformula = (List.chartformula != undefined ? List.chartformula : "");
			var axis = (List.axis != undefined ? List.axis : "");
			var yfieldaxis = 1;
			var zfieldaxis = 1;
			var fieldName = (List.fieldtype != undefined ? List.fieldtype : "");
			var colorcode = (List.colorcode == "rgb(233, 236, 239)" ? "#26a0fc" : List.colorcode);
			colors.push(colorcode);
			//var chartsettingsfieldname 	= 	(List.chartsettingsfieldname !=	undefined?List.chartsettingsfieldname:"");
			if (chartformula != "" && chartformula != undefined) {
				var textObj = { "fieldName": fieldName, "formula": chartformula, "period": datarangechart, "type": "freqTable" };
				$.ajax({
					url: "/stratroom/formula/kpiList?tableFrequency=" + measurement,
					type: "post",
					async: false,
					contentType: "application/json",
					data: JSON.stringify(textObj),
					success: function (data, status) {
						var fieldvalue = 1;
						var chartvalue = 1;
						var chartdata = [];
						var chartcolumndata = [];
						var chartwaterdata = [];
						var chartheatdata = [];
						var chartprogress = [];

						$.each(data, function (index, objval) {
							if (objval != "" && objval != undefined && !jQuery.isEmptyObject(objval)) {

								fieldName = fieldName.toLowerCase();
								$.each(objval, function (periodindex, quarterobj) {
									if (periodindex != "overallGap" && periodindex != "") {
										var actualbody = (quarterobj.actual != undefined ? quarterobj.actual : "");
										var targetbody = (quarterobj.target != undefined ? quarterobj.target : "");
										var gapbody = (quarterobj.gap != undefined ? quarterobj.gap : "");
										var budgetbody = (quarterobj.budget != undefined ? quarterobj.budget : "");
										var forecastbody = (quarterobj.forecast != undefined ? quarterobj.forecast : "");

										if (quarterobj.currency != undefined && quarterobj.currency != "") {
											currencyval = quarterobj.currency;
										}
										if ((actualbody.includes("M") || targetbody.includes("M")) || millions == true) {
											millions = true;
										}
										else if ((actualbody.includes("%") || targetbody.includes("%")) || percentage == true) {
											percentage = true;
										}

										if (typeof actualbody === "number") {
											actualbody = actualbody.toString();
										} if (typeof targetbody === "number") {
											targetbody = targetbody.toString();
										} if (typeof gapbody === "number") {
											gapbody = gapbody.toString();
										} if (typeof budgetbody === "number") {
											budgetbody = budgetbody.toString();
										} if (typeof forecastbody === "number") {
											forecastbody = forecastbody.toString();
										}


										actualbody = convertonumber(actualbody);
										targetbody = convertonumber(targetbody);
										gapbody = convertonumber(gapbody);
										budgetbody = convertonumber(budgetbody);
										forecastbody = convertonumber(forecastbody);

										if (fieldName == "actual") {
											chartvalue = actualbody;

										} else if (fieldName == "target") {
											chartvalue = targetbody;

										} else if (fieldName == "gap") {
											chartvalue = gapbody;

										} else if (fieldName == "budget") {
											chartvalue = budgetbody;

										} else if (fieldName == "forecast") {
											chartvalue = forecastbody;

										}
										if (layoutType == "BubbleChart") {
											var numberformat = (typeof actualbody === "number" ? convertInttoStringAndStringtoInt(actualbody) : actualbody);
											if (numberformat.indexOf("%") >= 0 && numberformat.indexOf(".") >= 0) {
												checkdecimalornot = true;
												percentage = true;
											} else if (numberformat.indexOf("%") >= 0) {
												percentage = true;
											} else if (numberformat.indexOf(".") >= 0) {
												checkdecimalornot = true;
											}
											var numberformat = (typeof targetbody === "number" ? convertInttoStringAndStringtoInt(targetbody) : targetbody);
											if (numberformat.indexOf("%") >= 0 && numberformat.indexOf(".") >= 0) {
												checkdecimalornot = true;
												percentage = true;
											} else if (numberformat.indexOf("%") >= 0) {
												percentage = true;
											} else if (numberformat.indexOf(".") >= 0) {
												checkdecimalornot = true;
											}
											chartdata.push({ "x": periodindex, "y": actualbody, "z": targetbody });
										}
										if (layoutType == "WaterfallChart") {
											var numberformat = (typeof chartvalue === "number" ? convertInttoStringAndStringtoInt(chartvalue) : chartvalue);
											if (numberformat.indexOf("%") >= 0 && numberformat.indexOf(".") >= 0) {
												checkdecimalornot = true;
												percentage = true;
											} else if (numberformat.indexOf("%") >= 0) {
												percentage = true;
											} else if (numberformat.indexOf(".") >= 0) {
												checkdecimalornot = true;
											}
											chartwaterdata.push({ "x": periodindex, "y": [actualbody, targetbody] });
										}
										if (layoutType == "HeatMap") {
											var numberformat = (typeof chartvalue === "number" ? convertInttoStringAndStringtoInt(chartvalue) : chartvalue);
											if (numberformat.indexOf("%") >= 0 && numberformat.indexOf(".") >= 0) {
												checkdecimalornot = true;
												percentage = true;
											} else if (numberformat.indexOf("%") >= 0) {
												percentage = true;
											} else if (numberformat.indexOf(".") >= 0) {
												checkdecimalornot = true;
											}
											chartheatdata.push({ "x": periodindex, "y": chartvalue });
										}
										if (layoutType == "ColumnChart" || layoutType == "LineChart" || layoutType == "AreaChart" || layoutType == "PieChart" || layoutType == "StackedChart" || layoutType == "MultiAxis" || layoutType == "StackedEcharts" || layoutType == "StackedHBcharts" || layoutType == "BarNegativeChart" || layoutType == "DoughnutROWcharts" || layoutType == "DoughnutRCcharts" || layoutType == "BarDatasetObjectArrayChart" || layoutType == "BarDynamicDataChart" || layoutType == "MixedLineBarChart"|| layoutType == "StackedAreaChart") {
											chartvalue = convertonumber(chartvalue);
											var numberformat = (typeof chartvalue === "number" ? convertInttoStringAndStringtoInt(chartvalue) : chartvalue);
											if (numberformat.indexOf("%") >= 0 && numberformat.indexOf(".") >= 0) {
												checkdecimalornot = true;
												percentage = true;
											} else if (numberformat.indexOf("%") >= 0) {
												percentage = true;
											} else if (numberformat.indexOf(".") >= 0) {
												checkdecimalornot = true;
											}
											chartcolumndata.push(chartvalue);
										}

										if (layoutType == "RadialMulti") {
											var progressvalue = 0;
											if (actualbody != "" && targetbody != "") {
												actualbody = Math.round(actualbody);
												targetbody = Math.round(targetbody);
												if (fieldName == "actual") {
													progressvalue = parseInt(actualbody);
												}

												if (fieldName == "target") {
													progressvalue = parseInt(targetbody);
												}
												if (isNaN(progressvalue)) {
													progressvalue = 0;
												}
											}
											chartprogress.push(progressvalue);
										}
										chartaxisfield.push(periodindex);

									}
								});

								if (layoutType == "BubbleChart") {
									chartdataload = { "name": displayname, data: chartdata };
								} else if (layoutType == "LineChart" || layoutType == "AreaChart" || layoutType == "PieChart" || layoutType == "StackedChart" || layoutType == "StackedEcharts" || layoutType == "StackedHBcharts" || layoutType == "BarNegativeChart" || layoutType == "DoughnutROWcharts" || layoutType == "DoughnutRCcharts" || layoutType == "BarDatasetObjectArrayChart" || layoutType == "BarDynamicDataChart" || layoutType == "MixedLineBarChart"|| layoutType == "StackedAreaChart") {
									chartdataload = { "name": displayname, data: chartcolumndata };
								} else if (layoutType == "WaterfallChart") {
									chartdataload = { "name": displayname, data: chartwaterdata };
								} else if (layoutType == "HeatMap") {
									chartdataload = { "name": displayname, "data": chartheatdata };
								} else if (layoutType == "MultiAxis") {
									chartdataload = { "name": displayname, "type": "column", data: chartcolumndata };
								} else if (layoutType == "ColumnChart") {
									chartdataload = { "name": displayname, "type": "column", data: chartcolumndata };
								} else if (layoutType == "RadialMulti") {
									chartdataload = { "name": displayname, data: chartprogress };
								}
							}
						});

					}

				});

			}
			chartdataloadval.push(chartdataload);
		});
		// each end
	}

	if (layoutType == "BubbleChart") {
		bubbleRender("-1", 'load', chartdataloadval, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval);
	} else if (layoutType == "ColumnChart") {
		columnRender("-1", 'load', chartdataloadval, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval);
	} else if (layoutType == "LineChart") {
		lineRender("-1", 'load', chartdataloadval, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval);
	} else if (layoutType == "AreaChart") {
		areaRender("-1", 'load', chartdataloadval, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval);
	} else if (layoutType == "PieChart") {
		pieRender("-1", 'load', chartdataloadval, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval);
	} else if (layoutType == "WaterfallChart") {
		waterfallRender("-1", 'load', chartdataloadval, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval);
	} else if (layoutType == "MultiAxis") {
		multiaxisRender("-1", 'load', chartdataloadval, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval);
	} else if (layoutType == "StackedChart") {
		stackedRender("-1", 'load', chartdataloadval, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval);
	} else if (layoutType == "RadialMulti") {
		radialmultipleRender("-1", 'load', chartdataloadval, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval);
	}
}


function getriskcustomscore() {
	$.ajax({
		type: "GET",
		url: "/stratroom/riskcustomscore",
		async: false,
		success: function (data) {
			customscore = data;


			$.each(customscore, function (index, custom) {

				if (custom.priority > 5) {
					likelihoodmap.set(custom.score, custom.priority);

				} else {
					impactmap.set(custom.score, custom.priority);
				}

			})
		}
	});
}

function heatmapchartviewSuccesscallback(item) {
	var chartdataloadval = [];
	var chartaxisfield = [];
	var checkdecimalornot = false;
	var percentage = false;
	var millions = false;
	var currencyval = "$";
	var colors = [];
	var layoutType = item.dashBoardPreferencesValue.type;
	var chartdisplayname = (item.dashBoardPreferencesValue.displayname != undefined && item.dashBoardPreferencesValue.displayname != "" ? item.dashBoardPreferencesValue.displayname : "");
	var risknames = item.dashBoardPreferencesValue.risknames;
	var datarangechart = ((item.dashBoardPreferencesValue.datarangechart != undefined && item.dashBoardPreferencesValue.datarangechart != "") ? item.dashBoardPreferencesValue.datarangechart : $("#datePeriod").val());
	var riskstatus = item.dashBoardPreferencesValue.riskstatus;
	var populate = false;
	/*if(risknames	!=	"" && risknames.indexOf(',') > 0){
		risknames	=	risknames.split(',');
	}else if(risknames	!=	""){
		risknames	=	risknames.split(',');
	}else{
		risknames	=	[];
	}*/

	if (riskstatus != "" && riskstatus.indexOf(',') > 0) {
		riskstatus = riskstatus.split(',');
	} else if (riskstatus != "") {
		riskstatus = riskstatus.split(',');
	} else {
		riskstatus = [];
	}


	if (risknames != "" && risknames != null && risknames != undefined) {
		if (riskLevel != "" && riskLevel != undefined && riskLevel != null && riskLevel != "All") {
			urlinitiative = "/stratroom/riskHeadListWithChild?riskIds=" + risknames + "&limit=" + riskLevel;
		}
	}


	if (risknames != "" && risknames != null && risknames != undefined) {
		populate = true
	}

	if (riskstatus != "" && riskstatus.indexOf(',') > 0) {
		populate = true
	}

	if (risknames && typeof risknames === "string") {
		var numericRiskIds = risknames.split(",")
			.map(name => name.trim())
			.filter(name => name !== "All" && name !== "undefined" && !isNaN(name) && Number.isInteger(Number(name)))
			.join(",");
	
		if (numericRiskIds) {
			if (riskLevel && riskLevel !== "All" && !isNaN(riskLevel) && Number.isInteger(Number(riskLevel))) {
				urlinitiative = "/stratroom/riskHeadListWithChild?riskIds=" + numericRiskIds + "&limit=" + riskLevel+"&dateRange="+datarangechart;;
			} else {
				urlinitiative = "/stratroom/riskHeadListWithChild?riskIds=" + numericRiskIds + "&limit=-1&dateRange="+datarangechart;
			}
		} else {
			console.error("Invalid riskIds provided.");
		}
	} else {
		console.error("risknames must be a non-empty string.");
	}

	if (populate) {
		$.ajax({
			url: urlinitiative,
			async: false,
			success: function (resdata) {
				var riskScores = {}; // Object to hold the scores and corresponding riskUniqueIds
				var inherentScores = {};
				$.each(resdata, function (status, data) {
					console.log(data, "datascore");

					var riskID = data.id;
					var flagcolor = "risk_green_color";
					var riskstatuscolor = "";
					var riskstatusvalue = "";
					if (data.riskValue.likeliHood == "Rare") {
						flagcolor = "risk_green_color";
						riskstatuscolor = "Very Low";
						riskstatusvalue = "Low";
					} else if (data.riskValue.likeliHood == "Unlikely") {
						flagcolor = "risk_yellow_color";
						riskstatuscolor = "Tolerable";
					} else if (data.riskValue.likeliHood == "Possible" || data.riskValue.likeliHood == "Likely" || data.riskValue.likeliHood == "Almost Certain") {
						flagcolor = "risk_red_color";
						riskstatuscolor = "Very High";
						riskstatusvalue = "High";
					}

					var riskstatuscolorFlag = false;

					console.log((data.riskValue.riskStatus).replaceAll(' ', ''));
					console.log(riskstatus);
					console.log(jQuery.inArray((data.riskValue.riskStatus).replaceAll(' ', ''), riskstatus));
					if (jQuery.inArray((data.riskValue.riskStatus).replaceAll(' ', ''), riskstatus) !== -1) {
						riskstatuscolorFlag = true;
					}

					if (riskstatus.length == 0) {
						riskstatuscolorFlag = true;
					}

					if (riskstatuscolorFlag == true) {
						var riskchartDataList = {
							id: data.id,
							name: (data.riskValue.name != undefined ? data.riskValue.name : ""),
							score: (data.riskValue.score != undefined ? data.riskValue.score : ""),
							impact: (data.riskValue.impact != undefined ? data.riskValue.impact : ""),
							likeliHood: (data.riskValue.likeliHood != undefined ? data.riskValue.likeliHood : "")
						};
						chartdataloadval.push(riskchartDataList);
					}

					var inherentscore = data.inherentRiskConsequenceScore;
					if (inherentscore) {
						if (!inherentScores[inherentscore]) {
							inherentScores[inherentscore] = [];
						}
						inherentScores[inherentscore].push(data.riskUniqueId);
					}
					var riskscore = data.residualRiskImpactScore;
					if (riskscore) {
						if (!riskScores[riskscore]) {
							riskScores[riskscore] = [];
						}
						riskScores[riskscore].push(data.riskUniqueId);
					}
					console.log(riskScores, "riskscore");
					console.log(inherentScores, "inherentscore");
					tablerows += `<tr>
									<td>${data.riskValue.department}</td>
									<td>${data.riskUniqueId}</td>
									<td>${data.riskValue.name}</td>
									<td>${data.inherentRiskConsequenceScore}</td>
									<td>${data.residualRiskImpactScore}</td>
									<td>${data.riskValue.riskStatus}</td>
								  </tr>`;
				});

				var tablebody = `<div id="submainriskEventOccurenceContainer">
								   <table class="table table-bordered w-100 table-centered" style="margin-bottom: 0px !important;white-space:nowrap;">
										<thead>
											<tr>
												<th data-i18n="Department Name">Department Name</th>
												<th>Risk Code</th>
												<th>Risk Name</th>
												<th>Inherent Risk Score</th>
												<th>Residual Risk Score</th>
												<th>Risk Level</th>
											</tr>
										</thead>
										<tbody>${tablerows}</tbody>
									</table>
								  </div>`;

				$("#cardtableheat" + item.id).html(tablebody);

				// Pass inherentScores and riskScores to heatmapRender
				heatmapRender(item.id, 'load', chartdataloadval, chartdisplayname, inherentScores, riskScores);

				$(document).on('change', '#heatmapselection', function () {
					heatmapRender(item.id, 'load', chartdataloadval, chartdisplayname, inherentScores, riskScores);
				});
			}
		});



	} else {
		// Render chart without data if no risks are found
		heatmapRender(item.id, 'load', [], chartdisplayname);
	};
}


