function bubbleRender(id, type, chartdataload, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval) {
  console.log(id, type, chartdataload, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval, "bubble");

  var yaxisdata = "";
  if (millions) {
    yaxisdata = currencyval + " in Millions";
  } else if (percentage) {
    yaxisdata = "Value in %";
  } else {
    yaxisdata = "Value in #";
  }

  var options = {
    series: chartdataload,
    chart: {
      height: 323,
      type: "bubble",
      toolbar: { show: false },
      zoom: { enabled: true },
    },
    dataLabels: {
      enabled: false,
    },
    legend: {
      position: "bottom",
      horizontalAlign: "center",
      fontFamily: '"Poppins", sans-serif',
      fontSize: "13px",
    },
    fill: {
      opacity: 0.8,
    },
    colors: colors,
    stroke: {
      width: 1,
      colors: ['#fff']
    },
    grid: {
      borderColor: '#e5e5e5',
      strokeDashArray: 3,
    },
    tooltip: {
      theme: "light",
      y: {
        formatter: function (val) {
          if (millions) return currencyval + " " + val + " M";
          if (percentage) return val + " %";
          return val;
        },
      },
    },
    xaxis: {
      tickAmount: 12,
      type: "category",
      title: {
        text: chartdisplayname || "Period",
        style: {
          fontFamily: '"Poppins", sans-serif',
          fontWeight: 500,
          fontSize: '13px',
        },
      },
      labels: {
        style: {
          fontFamily: '"Poppins", sans-serif',
        },
      },
    },
    yaxis: {
      max: 70,
      title: {
        text: yaxisdata,
        style: {
          fontFamily: '"Poppins", sans-serif',
          fontWeight: 500,
          fontSize: '13px',
        },
      },
      labels: {
        style: {
          fontFamily: '"Poppins", sans-serif',
        },
      },
    },
  };

  var chart1 = new ApexCharts(
    document.querySelector("#Bubblechart" + id),
    options
  );
  chart1.render();

  var chart2 = new ApexCharts(
    document.querySelector("#Bubblelarge" + id),
    options
  );
  chart2.render();
}


