function BarDatasetObjectArrayChartRender(id, type, chartdataload, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval) {
    var yaxislabel = chartaxisfield || [];
    var yaxisdata = "";
    
    if (millions) { yaxisdata = (currencyval || '') + " in Millions"; } 
    else if (percentage) { yaxisdata = "Value in %"; } 
    else { yaxisdata = "$ (thousand)"; }

    var dimensions = ['category'];
    var source = [];
    var series = [];
    
    if (Array.isArray(chartdataload) && chartdataload.length > 0) {
        chartdataload.forEach(function(item, index) {
            dimensions.push(item.name || ('Series ' + (index + 1)));
        });
        
        yaxislabel.forEach(function(category, idx) {
            var row = { category: category };
            chartdataload.forEach(function(item) {
                var val = (item.data || [])[idx] || 0;
                if (typeof val === 'string') {
                    val = parseFloat(val.replace(/[^0-9.-]/g, '')) || 0;
                }
                row[item.name || 'Series'] = val;
            });
            source.push(row);
        });
        
        for (var i = 1; i < dimensions.length; i++) {
            series.push({
                type: 'bar',
                itemStyle: { color: colors && colors[i-1] ? colors[i-1] : undefined }
            });
        }
    }

    var option = {
        tooltip: { 
            trigger: 'axis', 
            axisPointer: { type: 'shadow' }, 
            textStyle: { fontFamily: '"Poppins", sans-serif', fontSize: 12 } 
        },
        legend: { 
            data: dimensions.slice(1), 
            textStyle: { fontFamily: '"Poppins", sans-serif', fontSize: 13 },
            top: 0,        // CHANGED: Moved to top
            bottom: 'auto' // CHANGED: Removed from bottom
        },
        dataset: { dimensions: dimensions, source: source },
        grid: { 
            left: '12%',   
            right: '8%', 
            bottom: '10%', // CHANGED: Reduced from 12% since legend is at top
            top: '20%',    // CHANGED: Increased from 15% for legend at top
            containLabel: true 
        },
        xAxis: { 
            type: 'category', 
            name: chartdisplayname,
            nameLocation: 'middle',
            nameGap: 45,
            nameTextStyle: { fontFamily: '"Poppins", sans-serif', fontSize: 12 },
            axisLabel: { 
                rotate: 45, 
                interval: 0, 
                fontSize: 10, 
                fontFamily: '"Poppins", sans-serif',
                margin: 12,
                width: 100,
                overflow: 'break'
            }
        },
        yAxis: {
            type: 'value',
            name: yaxisdata,
            nameLocation: 'middle',
            nameGap: 40,
            nameTextStyle: { fontFamily: '"Poppins", sans-serif', fontSize: 12 },
            axisLabel: {
                fontSize: 10, 
                fontFamily: '"Poppins", sans-serif',
                formatter: function(value) {
                    if (percentage) return value + '%';
                    if (millions) return (value / 1000000).toFixed(1) + 'M';
                    return value;
                }
            }
        },
        series: series,
        color: colors || ['#008FFB', '#00E396', '#feb019', '#f02fc2', '#607d8b']
    };

    renderChart("#BarDatasetObjectArrayChart" + id, option, '323px');
    renderChart("#BarDatasetObjectArrayChartlarge" + id, option, '600px');
}

function BarDynamicDataChartRender(id, type, chartdataload, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval) {

    var yaxislabel = chartaxisfield || [];
    var yaxisdata = "";

    if (millions) {
        yaxisdata = (currencyval || '') + " in Millions";
    } else if (percentage) {
        yaxisdata = "Value in %";
    } else {
        yaxisdata = "$ (thousand)";
    }

    var chartInstances = {};
    var displayCount = 5;

    var bufferData = {
        categories: [],
        series: []
    };

    if (Array.isArray(chartdataload) && chartdataload.length > 0) {

        chartdataload.forEach(function (item, index) {

            var rawData = item.data || item.value || [];

            var cleanData = rawData.map(function (val) {
                if (typeof val === 'string') {
                    var num = parseFloat(val.replace(/[^0-9.-]/g, ''));
                    return isNaN(num) ? 0 : num;
                }
                return typeof val === 'number' ? val : 0;
            });

            bufferData.series.push({
                name: item.name || ('Series ' + (index + 1)),
                data: cleanData.slice(0, displayCount),
                itemStyle: {
                    color: colors && colors[index] ? colors[index] : undefined
                }
            });

        });

        bufferData.categories = yaxislabel.slice(0, displayCount);
    }

    var option = {

        tooltip: {
            trigger: 'axis',
            axisPointer: {
                type: 'cross',
                label: { backgroundColor: '#283b56', fontSize: 12 }
            },
            textStyle: { fontFamily: '"Poppins", sans-serif', fontSize: 12 }
        },

        legend: {
            data: chartdataload.map(item => item.name),
            textStyle: { fontFamily: '"Poppins", sans-serif', fontSize: 13 },
            top: 0
        },

        grid: {
            left: '12%',
            right: '8%',
            bottom: '10%',
            top: '20%',
            containLabel: true
        },

        xAxis: {
            type: 'category',
            boundaryGap: true,
            data: bufferData.categories,
            name: chartdisplayname,
            nameLocation: 'middle',
            nameGap: 45,
            nameTextStyle: { fontFamily: '"Poppins", sans-serif', fontSize: 12 },
            axisLabel: {
                rotate: 45,
                interval: 0,
                fontSize: 10,
                fontFamily: '"Poppins", sans-serif',
                margin: 12,
                width: 100,
                overflow: 'break'
            }
        },

        yAxis: {
            type: 'value',
            name: yaxisdata,
            nameLocation: 'middle',
            nameGap: 40,
            nameTextStyle: { fontFamily: '"Poppins", sans-serif', fontSize: 12 },
            scale: true,
            boundaryGap: [0.2, 0.2],
            axisLabel: {
                fontSize: 10,
                fontFamily: '"Poppins", sans-serif',
                formatter: function (value) {
                    if (percentage) return value + '%';
                    if (millions) return (value / 1000000).toFixed(1) + 'M';
                    return value;
                }
            }
        },

        series: bufferData.series.map(function (s, i) {
            return {
                name: s.name,
                type: i === 2 ? 'line' : 'bar',
                symbol: i === 2 ? 'circle' : 'none',
                symbolSize: i === 2 ? 8 : 0,
                lineStyle: i === 2 ? { width: 3 } : {},
                data: s.data,
                itemStyle: s.itemStyle,
                emphasis: { focus: 'series' },
                label: {
                    show: i === 2,
                    position: 'top',
                    fontSize: 9,
                    fontFamily: '"Poppins", sans-serif',
                    distance: 5
                }
            };
        }),

        color: colors || ['#008FFB', '#00E396', '#feb019']
    };


    function renderWithAnimation(containerSelector, height) {

        var chartDom = document.querySelector(containerSelector);
        if (!chartDom) return null;

        chartDom.style.height = chartDom.style.height || height;
        chartDom.style.width = '100%';

        if (chartDom._echartsInstance) {
            chartDom._echartsInstance.dispose();
        }

        var chart = echarts.init(chartDom, null, { renderer: 'canvas' });
        chart.setOption(option);
        chartDom._echartsInstance = chart;

        chartDom._fullData = {
            categories: yaxislabel,
            series: chartdataload.map(function (item) {

                var rawData = item.data || item.value || [];

                return rawData.map(function (val) {
                    if (typeof val === 'string') {
                        var num = parseFloat(val.replace(/[^0-9.-]/g, ''));
                        return isNaN(num) ? 0 : num;
                    }
                    return typeof val === 'number' ? val : 0;
                });

            })
        };

        if (!chartDom._animationInterval) {

            var currentIndex = displayCount;

            chartDom._animationInterval = setInterval(function () {

                var fullData = chartDom._fullData;
                if (!fullData) return;

                // update categories
                bufferData.categories.shift();
                bufferData.categories.push(
                    fullData.categories[currentIndex % fullData.categories.length]
                );

                // update series
                var newSeriesData = bufferData.series.map(function (s, sIdx) {

                    var data = fullData.series[sIdx] || [];

                    s.data.shift();
                    s.data.push(data[currentIndex % data.length] || 0);

                    return s.data;

                });

                chart.setOption({
                    xAxis: { data: bufferData.categories },
                    series: bufferData.series.map(function (s, idx) {
                        return { data: newSeriesData[idx] };
                    })
                });

                currentIndex++;

            }, 2100);
        }

        setTimeout(function () {
            chart.resize();
        }, 50);

        return chart;
    }


    chartInstances.small = renderWithAnimation("#BarDynamicDataChart" + id, '323px');
    chartInstances.large = renderWithAnimation("#BarDynamicDataChartlarge" + id, '600px');


    var container = document.querySelector("#BarDynamicDataChart" + id);
    if (container) container._chartInstances = chartInstances;


    var modalParent = document.querySelector("#BarDynamicDataChartlarge" + id)?.closest('.modal');

    if (modalParent && chartInstances.large) {
        modalParent.addEventListener('shown.bs.modal', function () {
            chartInstances.large.resize();
        });
    }


    window.addEventListener('resize', function () {

        if (chartInstances.small) chartInstances.small.resize();
        if (chartInstances.large) chartInstances.large.resize();

    });

}
