function lineRender(id, type, chartdataload, chartaxisfield, millions, percentage, chartdisplayname, colors, currencyval) {
	var min = 0;
	var max = 0;
	var yaxisdata = ""
	if (millions) {
		yaxisdata = currencyval + " in Millions"
	}
	else if (percentage) {
		yaxisdata = "Value in %"
	}
	else {
		yaxisdata = "Value ($)"
	}
	$.each(chartdataload, function (val, item) {
		if (item.data != undefined && item.data.length > 0) {

			var newmax = item.data.reduce(function (a, b) {
				return Math.max(a, b);
			});

			max = newmax;
			if (newmax > max) {
				max = newmax;
			}

		} else {
			max = 1000;
		}
	});

	if (typeof min === "string") {
		min = parseInt(min);
	}
	if (typeof max === "string") {
		max = parseInt(max);
	}

	var xaxis = [];
	var yaxis = [];
	var percentage = false;
	var checkdecimalornot = false;
	var yaxislabel = chartaxisfield;
	var layout = {
		series: chartdataload,
		chart: {
			height: 323,
			type: "line",
			dropShadow: {
				enabled: true,
				color: "#000",
				top: 18,
				left: 7,
				blur: 10,
				opacity: 0.2,
			},
			toolbar: {
				show: true,
			},
		},
		stroke: {
			curve: "smooth",
		},
		dataLabels: {
			enabled: true
		},
		grid: {
			borderColor: "#e7e7e7",
			row: {
				colors: ["#f3f3f3", "transparent"], // takes an array which will
				// be repeated on columns
				opacity: 0.5,
			},
		},
		markers: {
			size: 1,
		},
		legend: {
			position: "bottom",
			horizontalAlign: "center",
		},
		colors: colors,
		xaxis: {
			categories: yaxislabel,
			title: {
				text: chartdisplayname,
				font: {
					family: '"Poppins", sans-serif'
				}
			}
		},
		yaxis: {
			title: {
				text: yaxisdata,
				font: {
					family: '"Poppins", sans-serif'
				}
			},
			min: min,
			max: max,
		}
	};


	var chart = new ApexCharts(
		document.querySelector("#Linechart" + id),
		layout
	).render();
	var bubbleChart = new ApexCharts(
		document.querySelector("#Linelarge" + id),
		layout
	).render();
}

