function caldenderupdateReportTempDataTableLoad(item) {
    var tableElement = $(".reportable_" + item.id);
    $(tableElement).empty();
    var layoutType = item.dashBoardPreferencesValue.type;
    var displayname = ((item.dashBoardPreferencesValue.displayname != undefined && item.dashBoardPreferencesValue.formula != "") ? item.dashBoardPreferencesValue.displayname : "Report Template Table");
    var datarangechart = ((item.dashBoardPreferencesValue.datarangechart != undefined && item.dashBoardPreferencesValue.datarangechart != "") ? item.dashBoardPreferencesValue.datarangechart : $("#datePeriod").val());
    var reportnames = item.dashBoardPreferencesValue.reportnames;

    var tablerow = "";
    var tableheader = "";

    // ✅ dynamically build headers
    if (item.dashBoardPreferencesValue.straoutcomes) tableheader += "<th>STRATEGIC OUTCOMES</th>";
    if (item.dashBoardPreferencesValue.straobjectives) tableheader += "<th>STRATEGIC OBJECTIVES</th>";
    if (item.dashBoardPreferencesValue.coherentActions) tableheader += "<th>COHERENT ACTIONS</th>";
    if (item.dashBoardPreferencesValue.subActions) tableheader += "<th>SUB-ACTIONS</th>";
    if (item.dashBoardPreferencesValue.output) tableheader += "<th>OUTPUT</th>";
    if (item.dashBoardPreferencesValue.responsibile) tableheader += "<th>RESPONSIBLE</th>";
    if (item.dashBoardPreferencesValue.target) tableheader += "<th>TARGET PERIOD 2024/25</th>";
    if (item.dashBoardPreferencesValue.planImp) tableheader += "<th>PLANNED IMPLEMENTATION <br> MONTHS</th>";
    if (item.dashBoardPreferencesValue.actualImp) tableheader += "<th>ACTUAL IMPLEMENTATION <br> MONTHS</th>";
    if (item.dashBoardPreferencesValue.performanceStatus) tableheader += "<th>PERFORMANCE STATUS AS AT <br> 30 SEPTEMBER 2024</th>";
    if (item.dashBoardPreferencesValue.impRemarks) tableheader += "<th>IMPLEMENTATION REMARKS</th>";
    if (item.dashBoardPreferencesValue.performanceAnalysis) tableheader += "<th>PERFORMANCE ANALYSIS <br> OBSERVATIONS RECOMMENDATIONS</th>";
    if (item.dashBoardPreferencesValue.consolidateimpRemarks) tableheader += "<th>CONSOLIDATED IMPLEMENTATION REMARKS</th>";
    if (item.dashBoardPreferencesValue.consolidateperformanceAnalysis) tableheader += "<th>CONSOLIDATED PERFORMANCE ANALYSIS <br> OBSERVATIONS RECOMMENDATIONS</th>";

    // ✅ Build API URL
    var urlinitiative = "";
    if (reportnames && typeof reportnames === "string") {
        var numericReportnames = reportnames
            .split(",")
            .map(name => name.trim())
            .filter(name => name !== "All" && name !== "undefined" && !isNaN(name))
            .join(",");
        if (numericReportnames) {
            urlinitiative = "/stratroom/initiativesListWithChild?initiativeIds=" + numericReportnames + "&dateRange=" + datarangechart;
        }
    }

    $.ajax({
        url: urlinitiative,
        async: false,
        success: function (redata) {
            console.log(redata, "reviewmoni");

            // ✅ group by department
            var departments = {};
            $.each(redata, function (status, List) {
                var deptName = List.initiativeValue.dept || "Unknown Department";
                if (!departments[deptName]) departments[deptName] = [];
                departments[deptName].push(List);
            });

            // ✅ render department groups
            for (var deptName in departments) {
                var deptData = departments[deptName];
                var safeDept = deptName.replace(/\s+/g, "_").replace(/[^\w]/g, "");

                // Department header row
                tablerow += `
                    <tr class="department-header bg-light fw-bold">
                        <td colspan="${tableheader.split('<th>').length - 1}" 
                            style="border:1px solid #dee2e6;background-color: rgba(var(--stratroom-primary-rgb), 0.1);">
                            <span style="cursor:pointer;" onclick="toggleDepartmentRows(this, '${safeDept}')">
                                <i class="fas fa-plus-circle me-2"></i>${deptName}
                            </span>
                        </td>
                    </tr>`; 

                // ✅ Initiative Rows
                $.each(deptData, function (index, List) {
					
					 const latestPref = (item.preferenceDetailList || [])
        .filter(p => p.recordId === List.id)
        .sort((a, b) => b.id - a.id)[0]; // latest by ID

    const consolidateimpRemarksval = latestPref?.preferenceValue?.consolidateimpRemarksval || "";
    const consolidateperformanceAnalysisval = latestPref?.preferenceValue?.consolidateperformanceAnalysisval || "";
	const performanceAnalysis = latestPref?.preferenceValue?.performanceAnalysis || "";

                    tablerow += `<tr class="department-row-${safeDept}" style="display:none;">`;

                    if (item.dashBoardPreferencesValue.reportId)
                        tablerow += `<td>${List.id || ""}</td>`;
                    if (item.dashBoardPreferencesValue.straoutcomes)
                        tablerow += `<td>${List.initiativeValue.perspectiveName || ""}</td>`;
                    if (item.dashBoardPreferencesValue.straobjectives)
                        tablerow += `<td>${List.initiativeValue.objectiveDesc || ""}</td>`;
                    if (item.dashBoardPreferencesValue.coherentActions)
                        tablerow += `<td>${List.initiativeValue.name || ""}</td>`;
                   if (item.dashBoardPreferencesValue.subActions) {
    let subs = List.subInitiativeList?.map(s => {
        return `<span class="badge label-bg-blue">${s.subInitiativeValue.description || ""}</span>`;
    }).join(" ") || "";

    tablerow += `<td>${subs}</td>`;
}

                    if (item.dashBoardPreferencesValue.output) {
                        let outs = List.mileStonesList?.map(m => m.mileStonesValue.desc).join(", ") || "";
                        tablerow += `<td>${outs}</td>`;
                    }
                    if (item.dashBoardPreferencesValue.departmentName)
                        tablerow += `<td><span class="badge label-bg-green">${List.initiativeValue.dept || ""}</span></td>`;
					 if (item.dashBoardPreferencesValue.target)
                        tablerow += `<td></td>`;
                    if (item.dashBoardPreferencesValue.planImp)
                        tablerow += `<td>${List.initiativeValue.daterange || ""}</td>`;
                    if (item.dashBoardPreferencesValue.actualImp)
                        tablerow += `<td>${List.initiativeValue.actualdaterange || ""}</td>`;

                    // ✅ PERFORMANCE STATUS (Flag Color)
                    if (item.dashBoardPreferencesValue.performanceStatus) {
                        var flagStyle = "";
                        switch ((List.initiativeValue.statusIndicator || "").toLowerCase()) {
                            case "red":
                                flagStyle = `color:rgba(255, 26, 9, 1) !important; font-size:10px !important;`;
                                break;
                            case "green":
                                flagStyle = `color:rgba(0, 128, 0, 1) !important; font-size:10px !important;`;
                                break;
                            case "yellow":
                                flagStyle = `color:rgba(255, 215, 0, 1) !important; font-size:10px !important;`;
                                break;
                            default:
                                flagStyle = `color:gray !important; font-size:10px !important;`; 
                                break;
                        }
                        tablerow += `<td style="text-align: center;">
                                        <i class="fas fa-flag" style="${flagStyle}"></i>
                                     </td>`;
                    }

                    // ✅ IMPLEMENTATION REMARKS
                    if (item.dashBoardPreferencesValue.impRemarks) {
                        let subimpremarks = List.subInitiativeList?.map(subInitiative => subInitiative.subInitiativeValue.impremark || "").join(", ") || "";
                        tablerow += `<td>${subimpremarks}</td>`;
                    }

                    // ✅ PERFORMANCE ANALYSIS
                    if (item.dashBoardPreferencesValue.performanceAnalysis) {
                        let subPerformance = List.subInitiativeList?.map(subInitiative => subInitiative.subInitiativeValue.performance || "").join(", ") || "";
                        tablerow += `<td >${subPerformance}</td>`;
                    }

                    // ✅ CONSOLIDATED IMPLEMENTATION REMARKS
                    if (item.dashBoardPreferencesValue.consolidateimpRemarks) {
                        tablerow += `<td >
                            <textarea class="consolidate-remarks consolidateimpRemarksval"
                                data-id="${List.id}"
                                data-type="${item.id}"
                                data-field="consolidateimpRemarksval"
                                style="width:100%; resize:vertical; border:none; background:transparent; font-weight:bold; overflow:hidden;">${consolidateimpRemarksval}</textarea>
                        </td>`;
                    }

                    // ✅ CONSOLIDATED PERFORMANCE ANALYSIS
                    if (item.dashBoardPreferencesValue.consolidateperformanceAnalysis) {
                        tablerow += `<td>
                            <textarea class="consolidate-remarks consolidateperformanceAnalysisval"
                                data-id="${List.id}"
                                data-type="${item.id}"
                                data-field="consolidateperformanceAnalysisval"
                                style="width:100%; resize:vertical; border:none; background:transparent; font-weight:bold; overflow:hidden;">${consolidateperformanceAnalysisval}</textarea>
                        </td>`;
                    }

                    tablerow += `</tr>`;
                });
            }
        },
        error: readErrorMsg
    });

    // ✅ render table
    var body = `
            <table class="table table-sm table-bordered w-100" id="reportable_${item.id}">
                <thead class="text-center align-middle"><tr>${tableheader}</tr></thead>
                <tbody>${tablerow}</tbody>
            </table>`;
    $(".reportable_" + item.id).html(body);
	

	$(document).off("blur", ".consolidate-remarks").on("blur", ".consolidate-remarks", function () {
	const $this = $(this);
	const initiativeId = $this.data("id");
	const dashboardId = $this.data("type");

	// Get the nearest row and find the two fields inside it
	const $row = $this.closest("tr");
	const consolidateImpRemarks = $row.find(".consolidateimpRemarksval").val()?.trim() || "";
	const consolidatePerfAnalysis = $row.find(".consolidateperformanceAnalysisval").val()?.trim() || "";
	const performanceAnalysisval = $row.find(".performanceAnalysis").val()?.trim() || "";

	const productData = {
		daskboardId: dashboardId,
		recordId: initiativeId,
		recordType: "Initiatives & Projects",
		preferenceValue: {
			consolidateimpRemarksval: consolidateImpRemarks,
			consolidateperformanceAnalysisval: consolidatePerfAnalysis,
			performanceAnalysis:performanceAnalysisval
		}
	};

	$.ajax({
		url: "/stratroom/preferences",
		type: "put",
		contentType: "application/json",
		data: JSON.stringify(productData),
		success: function () {
			$.notify("Successfully Updated", {
				style: 'success',
				className: 'graynotify'
			});
			location.reload(true);
		},
		error: readErrorMsg
	});
});
}


// ✅ fixed toggle function
function toggleDepartmentRows(element, safeDept) {
    var icon = element.querySelector("i");
    var rows = document.querySelectorAll(".department-row-" + safeDept);

    if (icon.classList.contains("fa-plus-circle")) {
        icon.classList.replace("fa-plus-circle", "fa-minus-circle");
        rows.forEach((r) => (r.style.display = "table-row"));
    } else {
        icon.classList.replace("fa-minus-circle", "fa-plus-circle");
        rows.forEach((r) => (r.style.display = "none"));
    }
}


