// Function to populate department dropdown for specific chart
function populateDeptChartSelectForChart(itemId) {
    var selectElement = $("#dashboard_showlist_" + itemId + " .deptChart");
    
    // Clear existing options
    selectElement.empty();
    
    // DO NOT add "All Departments" option - only show API results
    
    // Get department data using your existing API
    $.ajax({
        url: "/stratroom/departmentReportees",
        async: true,
        success: function (deptList) {
            console.log("Departments for chart " + itemId + ":", deptList);
            
            // Add departments to the specific chart's dropdown
            deptList.forEach(dept => {
                selectElement.append('<option value="' + dept.id + '">' + dept.name + '</option>');
            });
        }
    });
}

function heatmapchartdaterangeupdateTriggerchart(item) {
	var layoutType = item.dashBoardPreferencesValue.type;
	var chartdisplayname = item.dashBoardPreferencesValue.displayname || "";
	var risknames = item.dashBoardPreferencesValue.risknames;
	var riskLevel = item.dashBoardPreferencesValue.riskLevel;
	var riskstatus = item.dashBoardPreferencesValue.riskstatus || "";
	var datarangechart = item.dashBoardPreferencesValue.datarangechart || $("#datePeriod").val();
	var largechart = $(".largechart");
	var chartnamefield = "Heatmap";
	var populate = !!(risknames || riskstatus);

	$(largechart).attr("id", "Heatmaplarge" + item.id);
	$("#Heatmaplarge" + item.id).empty();
	$("#" + chartnamefield + item.id).empty();

	var tablerows = "";
	var chartdataloadval = [];

	if (riskstatus) {
		riskstatus = riskstatus.split(',').map(status => status.trim());
	} else {
		riskstatus = [];
	}
	var urlinitiative = "";
if (risknames && typeof risknames === "string") {
    // Filter and process risknames
    var numericRiskNames = risknames
        .split(",")
        .map(name => name.trim())
        .filter(name => name !== "All" && name !== "undefined" && !isNaN(name) && Number.isInteger(Number(name)))
        .join(",");

    if (numericRiskNames) {
        if (riskLevel && riskLevel !== "All") {
            urlinitiative = "/stratroom/riskHeadListWithChild?riskIds=" + numericRiskNames + "&limit=" + riskLevel+"&dateRange="+datarangechart;
        } else {
            urlinitiative = "/stratroom/riskHeadListWithChild?riskIds=" + numericRiskNames + "&limit=-1&dateRange="+datarangechart;
        }
    }
}


	if (populate && urlinitiative != "") {
		$.ajax({
			url: urlinitiative,
			async: false,
			success: function (resdata) {
				var riskScores = {}; // Object to hold the scores and corresponding riskUniqueIds
				var inherentScores = {};
				$.each(resdata, function (status, data) {
					console.log(data, "datascore");

					var riskID = data.id;
					var flagcolor = "risk_green_color";
					var riskstatuscolor = "";
					var riskstatusvalue = "";
					if (data.riskValue.likeliHood == "Rare") {
						flagcolor = "risk_green_color";
						riskstatuscolor = "Very Low";
						riskstatusvalue = "Low";
					} else if (data.riskValue.likeliHood == "Unlikely") {
						flagcolor = "risk_yellow_color";
						riskstatuscolor = "Tolerable";
					} else if (data.riskValue.likeliHood == "Possible" || data.riskValue.likeliHood == "Likely" || data.riskValue.likeliHood == "Almost Certain") {
						flagcolor = "risk_red_color";
						riskstatuscolor = "Very High";
						riskstatusvalue = "High";
					}
		
					var riskstatuscolorFlag = false;
		
					console.log((data.riskValue.riskStatus).replaceAll(' ', ''));
					console.log(riskstatus);
					console.log(jQuery.inArray((data.riskValue.riskStatus).replaceAll(' ', ''), riskstatus));
					if (jQuery.inArray((data.riskValue.riskStatus).replaceAll(' ', ''), riskstatus) !== -1) {
						riskstatuscolorFlag = true;
					}
		
					if (riskstatus.length == 0) {
						riskstatuscolorFlag = true;
					}
		
					if (riskstatuscolorFlag == true) {
						var riskchartDataList = {
							id: data.id,
							name: (data.riskValue.name != undefined ? data.riskValue.name : ""),
							score: (data.riskValue.score != undefined ? data.riskValue.score : ""),
							impact: (data.riskValue.impact != undefined ? data.riskValue.impact : ""),
							likeliHood: (data.riskValue.likeliHood != undefined ? data.riskValue.likeliHood : "")
						};
						chartdataloadval.push(riskchartDataList);
					}
		
					var inherentscore = data.inherentRiskConsequenceScore;
					if (inherentscore) {
						if (!inherentScores[inherentscore]) {
							inherentScores[inherentscore] = [];
						}
						inherentScores[inherentscore].push(data.riskUniqueId);
					}
					var riskscore = data.residualRiskImpactScore;
					if (riskscore) {
						if (!riskScores[riskscore]) {
							riskScores[riskscore] = [];
						}
						riskScores[riskscore].push(data.riskUniqueId);
					}
					console.log(riskScores,"riskscore");
					console.log(inherentScores,"inherentscore");
					tablerows += `<tr>
									<td>${data.riskValue.department}</td>
									<td>${data.riskUniqueId}</td>
									<td>${data.riskValue.name}</td>
									<td>${data.inherentRiskConsequenceScore !== undefined ? data.inherentRiskConsequenceScore : ''}</td>

								<td>${data.residualRiskImpactScore !== undefined ? data.residualRiskImpactScore : ''}</td>

									<td>${data.riskValue.riskStatus}</td>
								  </tr>`;
				});

				var tablebody = `<div id="submainriskEventOccurenceContainer">
								   <table class="table dashboard-task-infos align-center dashboard-table" style="margin-bottom: 0px !important;white-space:nowrap;">
										<thead>
											<tr>
												<th data-i18n="Department Name">Department Name</th>
												<th>Risk Code</th>
												<th>Risk Name</th>
												<th>Inherent Risk Score</th>
												<th>Residual Risk Score</th>
												<th>Risk Level</th>
											</tr>
										</thead>
										<tbody>${tablerows}</tbody>
									</table>
								  </div>`;

				$("#cardtableheat" + item.id).html(tablebody);

				// Pass inherentScores and riskScores to heatmapRender
				heatmapRender(item.id, 'load', chartdataloadval, chartdisplayname, inherentScores, riskScores);

				$(document).on('change', '#heatmapselection', function () {
					heatmapRender(item.id, 'load', chartdataloadval, chartdisplayname, inherentScores, riskScores);
				});
			}
		});



	} else {
		// Render chart without data if no risks are found
		heatmapRender(item.id, 'load', [], chartdisplayname);
	}
}


function ganttchartdaterangeupdateTriggerchart(item) {
	var layoutType = item.dashBoardPreferencesValue.type;
	var chartdisplayname = (item.dashBoardPreferencesValue.displayname != undefined && item.dashBoardPreferencesValue.displayname != "" ? item.dashBoardPreferencesValue.displayname : "");
	var risknames = item.dashBoardPreferencesValue.risknames;
	var datarangechart = ((item.dashBoardPreferencesValue.datarangechart != undefined && item.dashBoardPreferencesValue.datarangechart != "") ? item.dashBoardPreferencesValue.datarangechart : $("#datePeriod").val());
	var riskstatus = item.dashBoardPreferencesValue.riskstatus;
	var largechart = $(".largechart");
	var chartnamefield = "";
	chartnamefield = "GanttMultichart";
	$(largechart).attr("id", "GanttMultilarge" + item.id);
	$("#GanttMultilarge" + item.id).empty();

	var chartdataloadval = [];
	var checkdecimalornot = false;
	var percentage = false;
	var millions = false;
	var currencyval = "$";
	var chartaxisfield = [];
	var colors = [];
	var populate = false;

	/*if(risknames	!=	"" && risknames	!=	undefined && risknames.indexOf(',') > 0){
		risknames	=	risknames.split(',');
	}else if(risknames	!=	"" && risknames	!=	undefined){
		risknames	=	risknames.split(',');
	}else{
		risknames	=	[];
	}*/

	if (riskstatus != "" && riskstatus != undefined && riskstatus.indexOf(',') > 0) {
		riskstatus = riskstatus.split(',');
	} else if (riskstatus != "" && riskstatus != undefined) {
		riskstatus = riskstatus.split(',');
	} else {
		riskstatus = [];
	}


	var urlinitiative = "/stratroom/initiativesListWithChild";
	if (risknames != "" && risknames != null && risknames != undefined) {
		urlinitiative = "/stratroom/initiativesListWithChild?initiativeIds=" + risknames
	}

	var chartdata = [];

	if (riskstatus != "" && riskstatus != undefined && riskstatus.indexOf(',') > 0) {
		populate = true
	}

	if (risknames != "" && risknames != null && risknames != undefined) {
		populate = true
	}

	
		$.ajax({
			url: urlinitiative,//"/stratroom/initiatives/"+initiativeID+"?loadFlag=true"
			async: false,
			success: function (resdata) {
				$.each(resdata, function (status, data) {
					var initiativeID = data.id
					var landingimagecolor = "";
					var initiativestatuscolor = "";
					var findprogressvalue = (data.initiativeValue.statusLight != undefined && data.initiativeValue.statusLight != "" ? data.initiativeValue.statusLight : "default_bar");
					if (findprogressvalue.search('progress-bar-success') != -1) {
						landingimagecolor = "chartgreenbarcircle";
						initiativestatuscolor = "Green";
					} else if (findprogressvalue.search('yellow_bar') != -1) {
						landingimagecolor = "chartyellowbarcircle";
						initiativestatuscolor = "Yellow";
					} else if (findprogressvalue.search('orange_bar') != -1) {
						landingimagecolor = "chartorangebarcircle";
						initiativestatuscolor = "Red";
					} else {
						landingimagecolor = "defaultchartbarimagecircle";
					}

					var initiativestatuscolorFlag = false;
					if (jQuery.inArray(initiativestatuscolor, riskstatus) !== -1) {
						initiativestatuscolorFlag = true;
					}

					if (riskstatus.length == 0) {
						initiativestatuscolorFlag = true;
					}

					var chartprogress = (data.initiativeValue.progressval == undefined || data.initiativeValue.progressval == undefined) ? 0 : data.initiativeValue.progressval;
					var chartfromdate = "";
					var charttodate = "";

					var budgetValue = "$0";
					if (data.initiativeValue.budgetValue != undefined) {
						var returnresult = specialcharsconvertToNumberFormat(data.initiativeValue.budgetValue);
						var readBudgetAmount = intergerHumanFormat(returnresult['number']);
						budgetValue = returnresult['currency'] + readBudgetAmount;
					}

					var utilizedcurrency = "";
					if (data.initiativeValue.Utillized != undefined) {
						var returnresult = specialcharsconvertToNumberFormat(data.initiativeValue.Utillized);
						var readUtillizedAmount = intergerHumanFormat(returnresult['number']);
						if (data.initiativeValue.utilizedCurr != undefined && data.initiativeValue.Utillized != undefined) {
							utilizedcurrency = data.initiativeValue.utilizedCurr
								+ readUtillizedAmount;
						}
					}

					var balancecurrency = "";
					if (data.initiativeValue.Balance != undefined) {
						var returnresult = specialcharsconvertToNumberFormat(data.initiativeValue.Balance);
						var readBalanceAmount = intergerHumanFormat(returnresult['number']);
						if (data.initiativeValue.Balance != undefined && data.initiativeValue.BalCurr != undefined) {
							balancecurrency = data.initiativeValue.BalCurr
								+ readBalanceAmount;
						}
					}

					if (data.initiativeValue.daterange && data.initiativeValue.daterange.includes("-")) {
						var dateval = data.initiativeValue.daterange.split('-');
						chartfromdate = dateformatyymmdd(new Date(dateval[0]));
						charttodate = dateformatyymmdd(new Date(dateval[1]));
					}

					if (initiativestatuscolorFlag == true) {
						chartdataloadval.push({
							custom_class: 'activities-gantt-color', 'name': data.initiativeValue.name, 'start': chartfromdate
							, 'end': charttodate, 'progress': chartprogress, "budget": budgetValue, "utillized": utilizedcurrency, "balance": balancecurrency,
							"id": "Task " + i + data.id, "dependencies": "Task " + i + data.id
						});
					}
				});
			}
		});
	

	ganttRender(item.id, 'load', chartdataloadval, chartdisplayname);
}
