function populateDeptList(elementId) {
	$(elementId).empty();
	var numberOfOptions = $(elementId + ' > option').length;
	if (jQuery.isEmptyObject(deptlist)) {
		$.ajax({
			url: "/stratroom/departmentList",
			async: false,
			success: function (kpiListValue) {
				deptlist = kpiListValue;
				$.each(deptlist, function (index, kpiObj) {
					addOption(elementId, kpiObj, kpiObj)
				});
			}
		});
	} else if (numberOfOptions < 2) {
		$.each(deptlist, function (index, reportee) {
			addOption(elementId, reportee, reportee)
		});
	}
}

function populateDeptReporteeList() {
	const elements = [
		'.deptfilter',
		'.deptpos',
		'.deptTradingpos',
		'.deptrpo',
		'.deptriskEventFilter',
		'.riskcountdeptfilter',
		'.ermdeptfilter',
		'.deptcritical',
		'.deptreportTemplate',
		'.heatdeptfilter',
		'.deptinitiative',
		'.deptganttinitiative',
		'.riskeventfreqdeptfilter',
		'.kpidept',
		'.initiativeorgdepartmentmulti',
		'.initiativeprjdepartmentmulti',
		'.riskregisterdeptfilter'
	];

	// Clear existing options for all elements
	elements.forEach(elementId => {
		$(elementId).empty();
	});

	// Perform a single AJAX request to get the department reportees
	$.ajax({
		url: "/stratroom/departmentReportees",
		async: true,
		success: function (deptList) {
			console.log(deptList);
			// Add options to each element
			elements.forEach(elementId => {
				deptList.forEach(dept => {
					addOption(elementId, dept.name, dept.id);
				});
			});

		}
	});
}

