//Risk Rigister dept 
$('.riskregisterdeptfilter').change(function () {
	var selectedDeptIds = $(this).val(); // Get selected department IDs

	if (selectedDeptIds.length > 0) {
		var deptIds = selectedDeptIds.join(','); // Convert array to comma-separated string
		getRiskRegisterByDeptId('.reviewriskfilter', deptIds);
	} else {
		$('.reviewriskfilter').empty(); // Clear risks if no departments are selected
	}
});




function getRiskRegisterByDeptId(elementId, deptIds) {
	var $select = $(elementId);
	var currentSelections = $select.val() || [];

	$.ajax({
		url: "/stratroom/riskMonitoringListWithDeptids?deptIds=" + deptIds,
		async: false,
		method: "GET", // Corrected method property
		success: function (riskList) {
			$select.empty();
			addOption(elementId, 'All', 'All');
			var addedNames = new Set();

			$.each(riskList, function (index, risk) {
				if (!addedNames.has(risk.riskValue.name)) {
					addOption(elementId, risk.riskValue.name, risk.id);
					addedNames.add(risk.riskValue.name);
				}
			});

			currentSelections.forEach(function (value) {
				if ($select.find('option[value="' + value + '"]').length > 0) {
					$select.find('option[value="' + value + '"]').prop('selected', true);
				}
			});

			$select.trigger('change');
		},
		error: function () {
			console.error("Console Risk Monitoring Error");
		}
	});
}

