function populateInitiativeList(elementId, statuslist) {
	$(elementId).empty();
	var numberOfOptions = $(elementId + ' > option').length;
	if (jQuery.isEmptyObject(initiativelist)) {
		$.ajax({
			url: "/stratroom/initiativesListWithChild",///stratroom/initiativesList?status=nodate
			async: false,
			success: function (kpiListValue) {
				initiativelist = kpiListValue;
				if (statuslist != "" && statuslist != undefined && statuslist.length) {
					$.each(initiativelist, function (index, kpiObj) {
						$.each(statuslist, function (statusindex, statusObj) {
							var findprogressvalue = (kpiObj.initiativeValue.statusLight != undefined ? kpiObj.initiativeValue.statusLight : "");
							if (statusObj == "Green" && findprogressvalue.search('progress-bar-success') != -1) {
								addOption(elementId, kpiObj.initiativeValue.name, kpiObj.id)
							} else if (statusObj == "Yellow" && findprogressvalue.search('yellow_bar') != -1) {
								addOption(elementId, kpiObj.initiativeValue.name, kpiObj.id)
							} else if (statusObj == "Red" && findprogressvalue.search('orange_bar') != -1) {
								addOption(elementId, kpiObj.initiativeValue.name, kpiObj.id)
							}
						});
					});
				} else {
					$.each(initiativelist, function (index, kpiObj) {
						addOption(elementId, kpiObj.initiativeValue.name, kpiObj.id)
					});
				}
			}
		});
	} else if (numberOfOptions < 2) {
		if (statuslist != "" && statuslist != undefined && statuslist.length) {
			$.each(initiativelist, function (index, kpiObj) {
				$.each(statuslist, function (statusindex, statusObj) {
					var findprogressvalue = (kpiObj.initiativeValue.statusLight != undefined ? kpiObj.initiativeValue.statusLight : "");
					if (statusObj == "Green" && findprogressvalue.search('progress-bar-success') != -1) {
						addOption(elementId, kpiObj.initiativeValue.name, kpiObj.id)
					} else if (statusObj == "Yellow" && findprogressvalue.search('yellow_bar') != -1) {
						addOption(elementId, kpiObj.initiativeValue.name, kpiObj.id)
					} else if (statusObj == "Red" && findprogressvalue.search('orange_bar') != -1) {
						addOption(elementId, kpiObj.initiativeValue.name, kpiObj.id)
					}
				});
			});
		} else {
			$.each(initiativelist, function (index, kpiObj) {
				addOption(elementId, kpiObj.initiativeValue.name, kpiObj.id)
			});
		}
	}
}


