function populateRiskList(elementId, statuslist) {
	$(elementId).empty();
	var numberOfOptions = $(elementId + ' > option').length;
	console.log(risknameslist, "risklist")
	if (jQuery.isEmptyObject(risknameslist)) {
		$.ajax({
			url: "/stratroom/riskListWithChild",
			async: false,
			success: function (kpiListValue) {
				console.log(kpiListValue);
				risknameslist = kpiListValue;
				if (statuslist != "" && statuslist != undefined && statuslist.length) {
					$.each(risknameslist, function (index, kpiObj) {
						$.each(statuslist, function (statusindex, statusObj) {
							var riskstatuscolor = kpiObj.riskValue.likeliHood;
							var riskstatusValue = kpiObj.riskValue.riskStatus;
							if (statusObj == "Green" && riskstatuscolor == "Rare") {
								addOption(elementId, kpiObj.riskValue.name, kpiObj.id);
							} else if (statusObj == "Yellow" && riskstatuscolor == "Unlikely") {
								addOption(elementId, kpiObj.riskValue.name, kpiObj.id);
							} else if (statusObj == "Red" && (riskstatuscolor == "Possible" || riskstatuscolor == "Likely" || riskstatuscolor == "Almost Certain")) {
								addOption(elementId, kpiObj.name, kpiObj.id);
							}
						});
					});
				} else {
					$.each(risknameslist, function (index, kpiObj) {
						addOption(elementId, kpiObj.riskValue.name, kpiObj.id);
					});
				}

			}
		});
	} else if (numberOfOptions < 2) {
		if (statuslist != "" && statuslist != undefined && statuslist.length) {
			$.each(risknameslist, function (index, kpiObj) {
				$.each(statuslist, function (statusindex, statusObj) {
					var riskstatuscolor = kpiObj.riskValue.likeliHood;
					if (statusObj == "Green" && riskstatuscolor == "Rare") {
						addOption(elementId, kpiObj.riskValue.name, kpiObj.id);
					} else if (statusObj == "Yellow" && riskstatuscolor == "Unlikely") {
						addOption(elementId, kpiObj.riskValue.name, kpiObj.id);
					} else if (statusObj == "Red" && (riskstatuscolor == "Possible" || riskstatuscolor == "Likely" || riskstatuscolor == "Almost Certain")) {
						addOption(elementId, kpiObj.riskValue.name, kpiObj.id);
					}
				});
			});
		} else {
			$.each(risknameslist, function (index, kpiObj) {
				addOption(elementId, kpiObj.riskValue.name, kpiObj.id);
			});
		}
	}
}

function populateRiskLists(elementId, statuslist, deptid) {
	// Ensure deptid is an array to prevent the 'includes' error
	deptid = Array.isArray(deptid) ? deptid : [];
	console.log(deptid, "deptid");
	$(elementId).empty();
	let numberOfOptions = $(elementId + ' > option').length;
	console.log(risknameslist);

	if (jQuery.isEmptyObject(risknameslist)) {
		$.ajax({
			url: "/stratroom/riskListWithChild",
			async: false,
			success: function (kpiListValue) {
				console.log(kpiListValue);
				risknameslist = kpiListValue;
				if (statuslist && statuslist.length) {
					$.each(risknameslist, function (index, kpiObj) {
						if (deptid.includes(kpiObj.departmentId)) {
							$.each(statuslist, function (statusindex, statusObj) {
								let riskstatusValue = kpiObj.riskValue.riskStatus;
								if (statusObj == riskstatusValue) {
									addOption(elementId, kpiObj.riskValue.name, kpiObj.id);
								}
							});
						}
					});
				} else {
					$.each(risknameslist, function (index, kpiObj) {
						if (deptid.includes(kpiObj.departmentId)) {
							addOption(elementId, kpiObj.riskValue.name, kpiObj.id);
						}
					});
				}
			}
		});
	} else if (numberOfOptions < 2) {
		if (statuslist && statuslist.length) {
			$.each(risknameslist, function (index, kpiObj) {
				if (deptid.includes(kpiObj.departmentId)) {
					$.each(statuslist, function (statusindex, statusObj) {
						let riskstatusValue = kpiObj.riskValue.riskStatus;
						if (statusObj == riskstatusValue) {
							addOption(elementId, kpiObj.riskValue.name, kpiObj.id);
						}
					});
				}
			});
		} else {
			$.each(risknameslist, function (index, kpiObj) {
				if (deptid.includes(kpiObj.departmentId)) {
					addOption(elementId, kpiObj.riskValue.name, kpiObj.id);
				}
			});
		}
	}
}


