$('.riskstatusmulti').on('change', function () {

	var data = $(".riskstatusmulti option:selected").text();
	var statusitem = [];
	if (data != "" && data.indexOf('Yellow') != "-1") {
		statusitem.push('Yellow');
	}
	if (data != "" && data.indexOf('Green') != "-1") {
		statusitem.push('Green');
	}
	if (data != "" && data.indexOf('Red') != "-1") {
		statusitem.push('Red');
	}
	populateRiskList('.risknamesmulti', statusitem);
	var existriskid = $("#existriskid").val();
	if (existriskid != "") {
		var deptIds = [];
		var formulationDept = existriskid.split(',');
		$.each(formulationDept, function (index, module) {
			deptIds.push(module);
		});
		$(".risknamesmulti").val(deptIds);
	}
	//$(".riskstatusmulti").select2();
});

