$('.heatstatusmulti').on('change', function () {
	var data = $(".heatstatusmulti option:selected").text();
	var statusitem = [];

	if (data != "" && data.indexOf('Very Low') != "-1") {
		statusitem.push('Very Low');
	}
	if (data != "" && data.indexOf('Low') != "-1") {
		if (data.indexOf('Low', 6) == "8" || data.indexOf('Low', 0) == "0") {
			statusitem.push('Low');
		}
	}
	if (data != "" && data.indexOf('Tolerable') != "-1") {
		statusitem.push('Tolerable');
	}
	if (data != "" && data.indexOf('High') != "-1") {
		if (data.indexOf('High', 0) == "0" || data.indexOf('High', 0) == "3" || data.indexOf('High', 0) == "8" || data.indexOf('High', 0) == "9" || data.indexOf('High', 0) == "11" || data.indexOf('High', 0) == "12" || data.indexOf('High', 0) == "17" || data.indexOf('High', 0) == "20") {
			statusitem.push('High');
		}
	}
	if (data != "" && data.indexOf('Very High') != "-1") {
		statusitem.push('Very High');
	}
	// populateRiskLists('.heatnamesmulti', statusitem);
	var existriskid = $("#heatnamesmulti").val();

	var updatedOptions = $(".heatnamesmulti option").map(function () {
		return this.value;
	}).get();

	console.log(existriskid);
	if (Array.isArray(existriskid) && existriskid.length > 0) {
		var riskNames = [];
		var formulationDept = existriskid.split(',');

		// Filter out the IDs that do not exist in the updated options list
		$.each(existriskid, function (index, module) {
			if (updatedOptions.includes(module)) {
				riskNames.push(module);
			}
		});

		$(".heatnamesmulti").val(riskNames);
	}
});


